WHERE NOT EXISTS (SELECT 1 FROM "dhikr" WHERE texte_arabe = 'أَسْتَغْفِرُ اللهَ الّذِي لا إِلَـهَ إِلّا هُوَ الحَيُّ القَيُّومُ وَأَتُوبُ إِلَيْه. (3 مَرّات)');

-- source: https://islam.ms/evocations-invocations-protection-doua-citadelle-musulman-adhkar
INSERT INTO "dhikr" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Invocations et Évocations (‘Adhkâr) du Messager de Allāh : celui qui les récite matin et soir, rien ne lui nuit et est protégé par la volonté de Allāh.', 'رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً، وَ فِي الآخِرَةِ حَسَنَةً ، وَقِنَا عَذَابَ النَّارِ . رَبَّنَا لا تُزِغْ قُلُوبَنَا بَعدَ إِذْ هَدَيْتَنَا وَهَبْ لَنَا مِن لَدُنكَ رَحْمَةً، إِنَّكَ أَنتَ الوَهَّابُ.', '', 'Rabbanâ ’Atinâ fî d-dounyâ ḥaçanah, wa fi l-’âkhirati ḥaçanah, wa qinâ ʿadhâba n-nâr. Rabbanâ lâ touzigh qoulôubanâ baʿda ’idh hadaytanâ wa hab lanâ min ladounka raḥmah, ’innaka ’anta l-Wahhâb', '', '', 'dhikr, invocations, évocations, adhkâr'
WHERE NOT EXISTS (SELECT 1 FROM "dhikr" WHERE texte_arabe = 'رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً، وَ فِي الآخِرَةِ حَسَنَةً ، وَقِنَا عَذَابَ النَّارِ . رَبَّنَا لا تُزِغْ قُلُوبَنَا بَعدَ إِذْ هَدَيْتَنَا وَهَبْ لَنَا مِن لَدُنكَ رَحْمَةً، إِنَّكَ أَنتَ الوَهَّابُ.');

-- source: https://islam.ms/evocations-invocations-protection-doua-citadelle-musulman-adhkar
INSERT INTO "dhikr" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Invocations et Évocations (‘Adhkâr) du Messager de Allāh : celui qui les récite matin et soir, rien ne lui nuit et est protégé par la volonté de Allāh.', 'أعوذُ بِكلماتِ الله التّامّاتِ الّتي لا يُجاوِزُهُنّ بَرٌّ ولا فاجِر من شرِّ ما يَنزِلُ مِن السَّماء وما يَعرُج فيها ومِن شَرِّ ما ذَرَأ في الأرضِ وما يَخرُج مِنها ومِن شَرِّ فِتَنِ اللَّيلِ والنَّهار ومن شرِّ كُلِّ طارقٍ إلَّا طارِقا يَطرُقُ بِخيرٍ يَا رَحمن', '', '’aʿôudhou bikalimâti l-Lâhi t-tâmmâti al-latî lâ youjâwizouhounna barroun wa lâ fâjir min charri mâ yanzilou mina s-samâ’i wa mâ yaʿroujou fîhâ wa min charri mâ dhara’a fi l-’arḍi wa mâ yakhroujou minhâ wa min charri fitani l-layli wa n-nahâr wa min charri koulli ṭâriqin ’illâ ṭâriqan yaṭrouqou bikhayrin yâ Raḥmân', '', '', 'dhikr, invocations, évocations, adhkâr'
WHERE NOT EXISTS (SELECT 1 FROM "dhikr" WHERE texte_arabe = 'أعوذُ بِكلماتِ الله التّامّاتِ الّتي لا يُجاوِزُهُنّ بَرٌّ ولا فاجِر من شرِّ ما يَنزِلُ مِن السَّماء وما يَعرُج فيها ومِن شَرِّ ما ذَرَأ في الأرضِ وما يَخرُج مِنها ومِن شَرِّ فِتَنِ اللَّيلِ والنَّهار ومن شرِّ كُلِّ طارقٍ إلَّا طارِقا يَطرُقُ بِخيرٍ يَا رَحمن');

-- source: https://islam.ms/evocations-invocations-protection-doua-citadelle-musulman-adhkar
INSERT INTO "dhikr" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Invocations et Évocations (‘Adhkâr) du Messager de Allāh : celui qui les récite matin et soir, rien ne lui nuit et est protégé par la volonté de Allāh.', 'أَعُوذُ باللهِ مِنَ الشَّيْطَانِ الرَّجِيم', '', '’Aʿôudhou bi l-Lâhi mina ch-chayṭâni r-rajîm', '', '', 'dhikr, invocations, évocations, adhkâr'
WHERE NOT EXISTS (SELECT 1 FROM "dhikr" WHERE texte_arabe = 'أَعُوذُ باللهِ مِنَ الشَّيْطَانِ الرَّجِيم');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, NULL, '« ائتني بها »', 'Fais-la venir', NULL, 'Ce qui figure dans le ṣaḥīḥ de Mouslim, qu’un homme est venu auprès du Messager de Allāh et l’a interrogé à propos d’une esclave à lui, il aurait dit - selon cette version - : « J’ai dit: Ô Messager de Allāh, si je l’affranchissais? ». Il lui a alors répondu : (’ītinī bihā) Il l’a fit venir et le Messager lui dit alors: «أَيْنَ الله» (’ayna l-Lāh?) Elle a répondu: «فِي السَّمَاءِ» (fi s-samā). Il lui a dit: «مَنْ أَنَا» (man ’anā) ce qui signifie: « Qui suis-je ? Elle a dit : «أنت رسول الله» (’anta raçoulou l-Lāh) ce qui signifie : « Tu es le Messager de Allāh. Il dit :', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« ائتني بها »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, NULL, '« أعتقها فإنها مؤمنة »', 'Affranchis-la, elle est certes croyante', NULL, '(’aʿtighā fa’innahā mou’minah) Ce ḥadith n’est pas ṣaḥīḥ pour deux raisons : pour l’iḍṭirāb car il a été rapporté avec ces termes et avec l’expression: من ربُّك (man rabbouki ?) ce qui signifie : « Qui est ton Seigneur? » elle a dit «Allāh»; et avec les termes : « أين الله » (’ayna l-Lāh) elle a alors pointé le doigt vers le ciel; et avec les termes :', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« أعتقها فإنها مؤمنة »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, NULL, '« أتشهدين أن لا إله إلا الله »', 'Témoignes- tu qu’il n’est de dieu que Allāh?', NULL, '(’atach-hadīna ’an lā ’ilāha ’il-la l-Lāh?) elle a dit: « oui », il a dit:', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« أتشهدين أن لا إله إلا الله »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, 'moutawātir', '« أتشهدين أني رسول الله »', 'Témoignes- tu que je suis le messager de Allāh?', NULL, '(’atach-hadīna ’anni raçoulou I-Lāh?) elle a dit « oui » L’iḍṭirāb est le caractère d’un ḥadīth qui se rapporte à un seul et même événement mais qui est rapporté par plusieurs versions contradictoires, aucune d’entre elles n’étant prépondérante, sans qu’on puisse trouver d’interprétation ni de compatibilité de sens entre les versions. est nécessairement faible comme l’a dit le Ḥaliḍḥ Al-Iraqiyy. La deuxième raison: la version dans laquelle il est dit: (’ayna- Lāh) est contraire aux fondements, car parmi les fondements de la Charīʿah il y a qu’un individu n’est pas jugé musulman sur sa parole (Allāhou fi s-samā’) car cette parole est commune aux juifs, aux chrétiens et à d’autres qu’eux. Le fondement connu dans la Charīʿah de Allāh, c’est celui qui se trouve dans le ḥadīth moutawātir :', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« أتشهدين أني رسول الله »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, 'moutawātir', '« أمرت أن أقاتل الناس حتى يشهدوا أن لا إله إلا الله وأني رسول الله »', NULL, NULL, '(’oumirtou an ’ougātila n-nāça hattā yach-hadoū ’an lā ’ilāha ’il-la l-Lāhou wa ’anni raçoulou l-Lāh) Cela signifie que l’entrée en Islam par la prononciation des deux témoignages. Quant aux termes de la version de Malik « أتشهدين » (’atach-hadīna) ils sont conformes aux fondements. Si quelqu’un dit " Comment la version de Mouslim (’ayna l-Lāh) et elle a répondu (fi s-samā’) jusqu’à la fin du ḥadīth " serait-elle rejetée alors que Mouslim l’a rapportée dans son livre et tout ce que Mouslim a rapporté est sensé être sûr? La réponse est que les savants du ḥadīth ont rejeté un certain nombre de ḥadīth de Mouslim, les Mouḥaddith les ont cités dans leurs livres, par exemple le ḥadīth dans lequel le Messager aurait dit à un homme (’inna ’abī wa ’abāka fi n-nār) ce qui signifie : " Certes, mon père et ton père iront en enfer " et le ḥadīth dans lequel " il aurait dit qu’il sera donné à chaque musulman au Jour du jugement (fidā’an lahou mina l-yahoūdi wa n-naṣārā) " et de même le ḥadīth de ’Anas dans lequel il aurait dit: " J’ai fait la prière derrière le Messager de Allāh, ʿOumar et Abou Bakr et ils ne récitaient pas بِسْمِ اللَّهِ الرَّحْمَٰنِ الرَّحِيمِ ﴾ ﴿ ". Le premier a été jugé faible (ḍaʿīf) par le Ḥāfidh As-Souyoūṭiyy, le deuxième a été rejeté par Al- Boukhāriyy et le troisième a été jugé faible (ḍaʿīf) par Ach- Chāfiʿiyy et par un certain nombre de ḥāfidh. Le ḥadīth de la femme esclave, selon le sens apparent, est faux pour son opposition avec le ḥadīth moutawātir précédemment cité. Or, le texte qui contredit le moutawātir est faux s’il n’accepte pas d’interprétation. Les mouḥaddith et les savants spécialistes des fondements ont été en accord à ce sujet. Mais certains savants l’ont interprété selon le sens suivant: ils ont dit que (’ayna l-Lāh) signifie l’interrogation sur sa glorification de Allāh et que sa réponse (fi s-samā’) signifie qu’ll est plus puissant que tout autre et sait plus que tout autre. Quant à en retenir le sens apparent, c’est- à-dire que Allāh habiterait le ciel, c’est faux et rejeté en raison de ce qui a été établi. En effet, son sens apparent est manifestement faux car il signifierait qu’un mécréant qui dirait (Allāhou fi s-samā’) serait jugé croyant. Quant aux mouchabbihah, ils ont retenu le sens qui vient communément à l’esprit, ils se sont ainsi égarés et leur parole: Nous interprétons la parole " fi s-samā’ " par le fait que Allāh est au-dessus du Trône " ne les sauve pas de l’égarement. Par conséquent, ils auront ainsi confirmé à Son sujet un semblable qui serait l’écrit dans lequel Allāh a fait écrire :', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« أمرت أن أقاتل الناس حتى يشهدوا أن لا إله إلا الله وأني رسول الله »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', 'Al-Boukhāriyy et An- Naça’ïyy dans', NULL, NULL, '« إِنْ رَحْمَتِي سَبَقَتْ غَضَبِي »', NULL, NULL, '(’inna raḥmatī sabaqat ghaḍabī) c’est-à-dire que les manifestations de la volonté de faire miséricorde sont plus nombreuses que les manifestations de la volonté de châtier. Les anges sont une des manifestations de la volonté de faire miséricorde, ils sont plus nombreux que les gouttes de pluie et les feuilles des arbres. Le paradis est aussi une manifestation de la volonté de faire miséricorde et il est plus grand que l’enfer des milliers de fois. Le fait que ce livre se trouve au-dessus du Trône est confirmé. Le hadiths qui le prouve a été rapporté par Al-Boukhāriyy et An- Naça’ïyy dans As-Sounanou I-Koubra et d’autres qu’eux. La version de Ibnou Ḥibban est :', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« إِنْ رَحْمَتِي سَبَقَتْ غَضَبِي »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, NULL, '« لما خلق الله الخلق كتب في كتاب يكتبه على نفسه وهو موضوع فوق العرش إن رحمتي تغلب غضبي »', 'Lorsque Allāh a créé le monde, Il a fait écrire un écrit dans lequel il y a Sa promesse et qui se trouve au-dessus du Trône : certes les manifestations de Ma volonté de faire miséricorde sont plus nombreuses que les manifestations de Ma volonté de châtier', NULL, '(lammā khalaga l-Lāhou I-khalga kataba fī kitābin yaktoubouhou ʿalā nafsihi wa houwa mawḍoūʿoun fawqa l-ʿarchi : ’inna raḥmatī taghlibou ghaḍabī) Si quelqu’un essaye d’interpréter (fawqa) par (doūna), il lui est dit : l’interprétation des textes (ta’wīl) n’est permise qu’avec une preuve textuelle confirmée ou un argument rationnel catégorique. Or ils n’ont aucun des deux. De plus, il n’y a aucune preuve de l’obligation de faire le ta’wīl dans ce ḥadīth. Comment serait-ce le cas alors qu’un des savants a dit que la Table préservée est au-dessus du Trône ? Effectivement il n’a pas été mentionné de texte disant explicitement qu’elle est au-dessus du Trône ni qu’elle est en-dessous. Les deux cas restent possibles: que la Table préservée soit au-dessus du Trône et qu’elle soit en-dessous du Trône. Par conséquent, selon sa parole que Allāh serait au-dessus du Trône, le mouchabbih aura considéré que la Table préservée serait en égalité avec Allāh, c’est-à-dire que Allāh fait face à une partie du Trône et que la Table fait face à une autre partie du Trône. De plus, ceci revient à L’assimiler à Ses créatures car le fait de faire face à une chose compte parmi les attributs des créatures. La version de An-Naça’iyy dans As-Sounanou l-Koubra est la suivante:', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« لما خلق الله الخلق كتب في كتاب يكتبه على نفسه وهو موضوع فوق العرش إن رحمتي تغلب غضبي »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, 'Aboū Moūca Al-’Achʿariyy que le', NULL, '«إِذَا كَانَ أَحَدُكُمْ فِي صَلَاتِهِ فَإِنَّهُ يُنَاجِي رَبَّهُ فَلَا يَبْصُقَنَ فِي قِبْلَتِهِ وَلَا عَنْ يَمِينِهِ فَإِنَّ رَبَّهُ بَيْنَهُ وَبَيْنَ قِبْلَتِهِ »', 'Si l’un de vous est dans sa prière, certes il implore son Seigneur. Qu’il ne crache donc pas dans la direction de sa qiblah, ni à sa droite. Certes [la miséricorde del son Seigneur se trouve entre lui et sa qiblah', NULL, '(’idhā kāna ’aḥadoukoum fī ṣalātihi fa’innahou younājī rabbah; falā yabṣouqanna fī qiblatihi wa lā ʿan yamīnihi fa’inna rabbahou baynahou wa bayna qiblatih) Le sens qui n’est pas à retenir et qui vient communément à l’esprit de ce ḥadīth est que Allāh se trouverait entre celui qui fait sa prière et la qiblah; ceci est impossible car Allāh existe sans endroit Ce ḥadīth a une chaîne de transmission plus forte que celle du ḥadīth de la femme esclave. De même, Al-Boukhāriyy a rapporté aussi d’après Aboū Moūca Al-’Achʿariyy que le Messager de Allāh a dit :', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '«إِذَا كَانَ أَحَدُكُمْ فِي صَلَاتِهِ فَإِنَّهُ يُنَاجِي رَبَّهُ فَلَا يَبْصُقَنَ فِي قِبْلَتِهِ وَلَا عَنْ يَمِينِهِ فَإِنَّ رَبَّهُ بَيْنَهُ وَبَيْنَ قِبْلَتِهِ »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, NULL, '« ارْبَعُوا عَلَى أَنْفُسِكُمْ فَإِنَّكُمْ لَا تَدْعُونَ أَصَمَّ وَلَا غَائِباً إِنَّكُم تَدْعُونَ سَمِيعاً قَريباً والذي تدعونَهُ أَقْرَبُ إِلَى أَحَدِكُمْ مِنْ عُنْقِ رَاحِلَةِ أَحَدِكُم »', 'Epargnez vos forces, vous n’invoquez ni un sourd ni quelqu’un à la science duquel des choses échappent. Certes, vous invoquez Qui entend et Qui sait toute chose de vous', NULL, '(irbaʿoū ʿālā ’anfoucikoum fa’innakoum lā tadʿoūna ’aṣamma wa lā ghā’ibā; ’innakoum tadʿoūna samīʿan qarībā; wa l-ladhī tadʿoūnahou ’aqrabou ’ilā ’aḥadikoum min ʿounouqi rāḥilati ’aḥadikoum) Le sens qui n’est pas à retenir et qui vient communément à l’esprit de ce ḥadīth est que Allāh serait plus proche de ces compagnons du Prophète par la distance que le cou de leurs montures, ceci est impossible car Allāh existe sans endroit On répond alors à celui qui contredit : si tu considères le ḥadīth de la femme esclave selon le sens qui vient communément à l’esprit et ces deux ḥadīth selon leur sens qui vient communément à l’esprit, ta prétention que Allāh est dans le ciel est annulée. Si en revanche, tu interprétais ces deux ḥadīth et n’interprétais pas le ḥadīth de la femme esclave, ce serait alors un propos arbitraire c’est-à-dire une parole sans preuve. Tu serais alors concerné par la parole de Allāh :', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« ارْبَعُوا عَلَى أَنْفُسِكُمْ فَإِنَّكُمْ لَا تَدْعُونَ أَصَمَّ وَلَا غَائِباً إِنَّكُم تَدْعُونَ سَمِيعاً قَريباً والذي تدعونَهُ أَقْرَبُ إِلَى أَحَدِكُمْ مِنْ عُنْقِ رَاحِلَةِ أَحَدِكُم »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, NULL, '« الرَّاحِمُونَ يَرْحَمُهُمُ الرَّحْمَنُ ارْحَمُوا مَنْ فِي الْأَرْضِ يَرْحَمكُمْ مَنْ فِي السَّمَاءِ »', NULL, NULL, '(ar-rāḥimoūna yarḥamouhoumou r-Raḥman; ’irḥamoū man fi l- ’arḍi yarḥamkoum man fi s-samā’) qui signifie : « Les miséricordieux, Ar-Raḥmān leur fait miséricorde; soyez miséricordieux envers ceux qui sont sur terre, [ceux qui sont dans le ciel feront preuve de miséricorde envers vous ». Dans une autre version rapportée :', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« الرَّاحِمُونَ يَرْحَمُهُمُ الرَّحْمَنُ ارْحَمُوا مَنْ فِي الْأَرْضِ يَرْحَمكُمْ مَنْ فِي السَّمَاءِ »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, NULL, '« يَرْحَمْكُمْ أَهْلُ السَّمَاءِ »', 'Les habitants du ciel feront preuve de miséricorde envers vous', NULL, '(yarḥamkoum ’ahlou s-samā’) Cette version explique donc la première version car « La meilleure manière d’expliquer un ḥadīth transmis, c’est de le faire par une autre version de ce ḥadīth » comme l’a dit le Ḥafiḍḥ Al-ʿIraqiyy dans son ouvrage ’Alfiyyatou l-Ḥadith: (wa khayrou mā fassartahoū bi l- wārid). Ce qui est visé par l’expression (’ahlou s-samā’) « les habitants du ciel », ce sont les anges. On ne dit pas s’agissant de Allāh : (’Ahlou s-samā’) - L’habitant du ciel -. Ceci a été cité par le Ḥafiḍḥ Al-ʿIraqiyy dans son livre Al-’Amāliyy à la suite de ce ḥadīth et son expression est la suivante : « La parole du prophète أهل السماء (ahlou s-samā’) qui signifie : les gens du ciel est une preuve que ce qui est visé par la parole de Allāh :', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« يَرْحَمْكُمْ أَهْلُ السَّمَاءِ »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, NULL, '« الرَّاحِمُونَ يَرْحَمُهُمُ الرَّحْمَنُ ارْحَمُوا أَهْلَ الْأَرْضِ يَرْحَمْكُمْ أَهْلُ السَّمَاءِ »', NULL, NULL, '(ar-rāḥimoūna yarḥamouhoumou r-Raḥman; ’irḥamou ’ahla l ’arḍi yarḥamoukoum ’ahlou s-samā’) De plus, si Allāh habitait le ciel comme le prétendent certains Il empièterait sur l’espace des anges et ceci est impossible. En effet, il a été rapporté dans le ḥadīth :', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« الرَّاحِمُونَ يَرْحَمُهُمُ الرَّحْمَنُ ارْحَمُوا أَهْلَ الْأَرْضِ يَرْحَمْكُمْ أَهْلُ السَّمَاءِ »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, NULL, '« ما في السماء موضع أربع أصابع إلا وفيه ملك قائم أو راكع أو ساجد »', 'Il n’ya pas dans les cieux un espace de quatre doigts qui ne soit occupé par un ange debout ou en inclination ou en prosternation', NULL, '(mā fi s-samā’ mawḍiʿou ’arbaʿi ’aṣābiʿa ’il-lā wa fīhi malakoun qā’imoun ’aw rākiʿoun ’aw sājid) De même, le ḥadīth qu’a rapporté Al-Boukhāriyy et Mouslim de Aboū Saʿīd Al-Khoudriyy que le Messager a dit:', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« ما في السماء موضع أربع أصابع إلا وفيه ملك قائم أو راكع أو ساجد »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, NULL, '« أَلَا تَأْمَنُونِي وَأَنَا أَمِينُ مَنْ فِي السَّمَاءِ يَأْتِينِي خَبَرُ مَنْ فِي السَّمَاءِ صَبَاحاً وَمَسَاءً »', 'Ayez foi en ce que je dis. Ceux qui sont au ciel croient en mon honnêteté et en ma véracité dans la transmission de la révélation. Les nouvelles de ceux qui sont au ciel me parviennent matin et soir.', NULL, '(’alā ta’manoūnī wa ’anā ’amīnou man fi s-samā’ ya’tīnī khabarou man fi s-samā’i ṣabaḥan wa maçā’a) Ceux qui sont visés ici, ce sont également les anges. Et si celui qui est visé par (man fi s-samā’) était Allāh, la signification serait (ʿāli l-qadri jiddā) c’est-à-dire Celui Qui est plus puissant que tout autre et sait plus que tout autre Quant au ḥadīth de Zaynab Bintou Jaḥch, la femme du Prophète, dans lequel elle disait :', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« أَلَا تَأْمَنُونِي وَأَنَا أَمِينُ مَنْ فِي السَّمَاءِ يَأْتِينِي خَبَرُ مَنْ فِي السَّمَاءِ صَبَاحاً وَمَسَاءً »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, NULL, '« زَوْجَكُنَّ أَهَالِيكُنَّ وَزَوْجَنِيَ اللهُ مِنْ فَوْقِ سَبْعِ سَمَوَاتِ »', NULL, NULL, '(zawwajakounna ’ahālīkounna wa zawwajaniya l-Lāhou min fawqi sabʿi samawāt) il signifie: « [ô femmes] ce sont vos familles qui vous ont mariées alors que moi, c’est Allāh qui m’a mariée, mon mariage était inscrit au-dessus des sept cieux », c’est-à-dire que le mariage du Prophète avec elle est inscrit dans la Table Préservée. Cette inscription est spécifique à Zaynab, elle n’est pas générale. L’inscription générale concerne tout un chacun de sorte que tout mariage qui doit avoir lieu jusqu’à la fin du monde est effectivement inscrit. La Table quant à elle est effectivement au-dessus des sept cieux. Quant au ḥadīth dans lequel il y a :', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« زَوْجَكُنَّ أَهَالِيكُنَّ وَزَوْجَنِيَ اللهُ مِنْ فَوْقِ سَبْعِ سَمَوَاتِ »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, NULL, '« وَالَّذِي نَفْسِي بِيَدِهِ مَا مِنْ رَجُلٍ يَدْعُو امْرَأَتَهُ إِلَى فِرَاشِهِ فتَأْبَى عَلَيْهِ إِلَّا كَانَ الَّذِي فِي السَّمَاءِ سَاخِطَا عَلَيْهَا .... »', NULL, NULL, '(wa l-Ladhī nafsī biyadihi mā min rajoulin yadʿoū m-ra’atahou ’ilā firāchihi fata’bā ’il-lā kāna l-ladhī fi s-samā’i sākhiṭan ʿalayhā...) Ce ḥadīth aussi concerne les anges. La preuve en est la deuxième version qui est du degré du ṣaḥīḥ, plus connue que cette première et qui est :', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« وَالَّذِي نَفْسِي بِيَدِهِ مَا مِنْ رَجُلٍ يَدْعُو امْرَأَتَهُ إِلَى فِرَاشِهِ فتَأْبَى عَلَيْهِ إِلَّا كَانَ الَّذِي فِي السَّمَاءِ سَاخِطَا عَلَيْهَا .... »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, NULL, '« لَعَنَتْهَا الْمَلَائِكَةُ حَتَّى تُصْبِحَ »', 'Les anges la maudissent jusqu’à ce qu’elle parvienne au matin', NULL, '(laʿanat-hā l-malā’ikatou ḥattā touṣbiḥ) [rapportée par Ibnou Ḥibban et d’autres] Quant au ḥadīth de Aboū d-Dardā’ que le Prophète aurait dit:', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« لَعَنَتْهَا الْمَلَائِكَةُ حَتَّى تُصْبِحَ »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, NULL, '« رَبَّنَا الَّذِي فِي السَّمَاءِ تَقَدَّسَ اسْمُكَ »', NULL, NULL, '(rabbana l-ladhī fi s-samā’i taqaddaça s-mouk) il n’est pas fort (ṣaḥīḥ) mais il est faible (ḍaʿ if) comme l’a jugé Ibnou l-Lawziyy. Et s’il avait été jugé fort (ṣaḥīḥ), son cas aurait été comme celui du ḥadīth de la femme esclave. Quant au ḥadīth de Joubayr Ibnou Mouṭʿim, que le Prophète aurait dit:', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« رَبَّنَا الَّذِي فِي السَّمَاءِ تَقَدَّسَ اسْمُكَ »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, 'Ibnou ʿAbbās qu’il aurait dit', NULL, '« إِنَّ اللهَ عَلَى عَرْشِهِ فَوْقَ سَمَوَاتِهِ، وَسَمَوَاتُهُ فَوْقَ أَرَاضِيهِ مِثْلُ الْقُبة »', NULL, NULL, '(inna l-Laha ʿala "’archihi fawga samawatihi wa samawatouhou fawga ’aradihi mithlou l-goubbah) Le sens apparent et qu’il ne faut pas retenir serait que Allāh serait sur le trône au-dessus de Ses cieux et que Ses cieux sont au-dessus de Ses terres tels une coupole. Al-Boukhariyy ne l’a pas jugé comme fort. Il ne peut donc constituer un argument (ḥoujjah). Il y a d’autre part, dans sa chaîne de transmission, quelqu’un qui est faible; par conséquent, sa transmission ne peut pas être un argument, Ibnoul-Jawziyy a mentionné cela ainsi que d’autres, De même, pour ce qu’il a rapporté c’est-à-dire Al-Boukhāriyy dans son livre Khalqou ’Afʿali l-ʿIbād d’après Ibnou ʿAbbās qu’il aurait dit:', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« إِنَّ اللهَ عَلَى عَرْشِهِ فَوْقَ سَمَوَاتِهِ، وَسَمَوَاتُهُ فَوْقَ أَرَاضِيهِ مِثْلُ الْقُبة »');

-- source: https://islam.ms/explication-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du Ḥadīth Al-Jāriyah femme esclave', NULL, NULL, 'ṣaḥīḥ', '« لَمَّا كَلَّمَ اللهُ مُوسَى كَانَ نِدَاؤُهُ فِي السَّمَاءِ وَكَانَ اللهُ فِي السَّمَاءِ »', NULL, NULL, '(lammā kallama l-Lāhou Moūçā kāna nidā’ouhou fi s-samā’i wa kāna l-Lāhou fi s-samā’) Le sens apparent et qu’il ne faut pas retenir serait (que lorsque Allāh a parlé à Moūçā, Son appel aurait été dans le ciel et Allāh aurait été dans le ciel) Ce ḥadīth n’est pas confirmé. Par conséquent, il ne peut pas être pris pour preuve. Al-Boukhāriyy ne s’est pas astreint à ne citer que des ḥadīth ṣaḥīḥ -sûrs dans ce livre-là. Par conséquent, le simple fait qu’un ḥadīth y figure ne suffit pas pour pouvoir le juger sûr. Quant à la parole attribuée à Mālik (Allāhou fi s-samā’i wa ʿilmouhoū fi koulli makān lā yakhloū minhou chay’), elle n’est pas confirmée non plus de Mālik, n’ayant pas de chaîne de transmission jusqu’à lui et Aboū Dawoūd ne la lui a pas attribuée avec une chaîne de transmission forte. Il n’a fait que la citer dans son livre Al-Maracil et la simple citation ne constitue pas une authentification.', 1, 'hadiths, explication, al-jāriyah, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« لَمَّا كَلَّمَ اللهُ مُوسَى كَانَ نِدَاؤُهُ فِي السَّمَاءِ وَكَانَ اللهُ فِي السَّمَاءِ »');

-- source: https://islam.ms/explication-hadiths-jaria-versets-non-explicites
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Détails et explication concernant hādīth al-jāriyah', 'Ibnou Ḥibbān', NULL, NULL, '« حتى يشهدوا أَن لاَّ إِلـه إلاَّ الله وأنِّي رَسُولُ الله »', 'Jusqu’à ce qu’ils témoignent qu’il n’est de dieu que Allāh et que je suis le Messager de Allāh', 'ḥattâ yach-hadôu ’an lâ ’ilâha ’il-la l-Lâh wa ’annî raçôulou l-Lâh', 'Il y a un ḥadīth moutawâtir [ḥadīth rapporté par un grand nombre de compagnons, témoins auditifs ou oculaires, à un grand nombre de rapporteurs à chaque génération], qui a été rapporté par quinze ou seize compagnons. Dans ce ḥadīth moutawâtir le prophète ʿalayhi s-salâm dit: Ce ḥadīth signifie donc qu’on ne juge quelqu’un musulman que sur sa prononciation des deux témoignages. Le ḥadīth de al-Jariyah, dans sa version rapportée par Mouslim, comporte le sens que le Prophète se serait contenté de la parole (fi s-samâ’) de cette femme pour la juger musulmane, ce qui contredit le ḥadīth plus fort cité précédemment. Le maître de cette femme l’avait effectivement amenée pour que le Prophète vérifie qu’elle était croyante. Dans ce ḥadīth, le Prophète aurait demandé à la femme: (’ayna l-Lâh), elle aurait répondu: (fi s-samâ’) puis il lui aurait demandé (man ’anâ) « Qui suis-je ? » elle aurait répondu: « Le Messager de Allāh », il aurait alors dit à son maître: ce qui signifie: « Libère-la car elle est croyante ». De plus la version rapportée par Mouslim ne viendrait que d’un seul compagnon. En effet, le ḥadīth de al-Jariyah donne l’illusion qu’il suffirait que quelqu’un dise: (Allāh fi s-samâ’) pour être jugé croyant alors que ceci est contraire à la vérité. an-Nawawiyy, ar-Raziyy et d’autres qui ont commenté le livre de Mouslim n’ont pas pris ce ḥadīth selon le sens apparent mais ils ont dit que (‘ayna l-Lâh) vient dans le sens de l’interrogation sur la glorification et l’éminence de Allāh et non pas dans le sens de l’interrogation sur la localisation dans l’espace. Voir: L’Imam An-Nawawiyy explique le ḥadīth al-Jâriyah (ḥadīth de la femme esclave) En effet on dit dans la langue arabe (‘ayna foulân –‘ayna Untel– ?) dans le sens de quel degré a-t-il ? Quelle est l’élévation de son mérite ? D’autre part, lorsque l’on dit (fi s-samâ’), cela peut signifier, dans la langue arabe, la supériorité du mérite. C’est de cette manière que les deux savants du ḥadīth, an-Nawawiyy et ar-Râziyy, l’ont interprété: ils ne l’ont pas pris selon le sens apparent comme l’ont fait les assimilationnistes. Le ḥadīth a effectivement été rapporté par l’Imam Mouslim tel que nous l’avons cité mais il a aussi été rapporté dans les termes: (Qui est ton Seigneur ?) auxquels elle aurait répondu: « Allāh » [rapporté par Ibnou Ḥibbān], de même que par les termes: (’ayna l-Lâh) après lesquels elle aurait pointé le doigt vers le ciel [rapporté par al-Bayhaqiyy]. Il a enfin été rapporté dans les termes:', 1, 'hadiths, détails, explication, concernant'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« حتى يشهدوا أَن لاَّ إِلـه إلاَّ الله وأنِّي رَسُولُ الله »');

-- source: https://islam.ms/explication-hadiths-jaria-versets-non-explicites
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Détails et explication concernant hādīth al-jāriyah', NULL, NULL, NULL, '« إرحمُو من في الأرضِ يَرحَمُكُم من في السَّماء »', 'Soyez miséricordieux envers ceux qui sont sur terre, ceux qui sont dans les cieux seront alors miséricordieux avec vous', '’irḥamôu man fi l-’arḍi yarḥamoukoum man fi s-samâ’', 'Ce ḥadīth a également été rapporté dans les termes suivants:', 1, 'hadiths, détails, explication, concernant'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« إرحمُو من في الأرضِ يَرحَمُكُم من في السَّماء »');

-- source: https://islam.ms/explication-hadiths-jaria-versets-non-explicites
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Détails et explication concernant hādīth al-jāriyah', NULL, NULL, NULL, '« إرحمُو أهلَ الأرضِ يَرحَمُكُم أهلُ السَّماء »', NULL, '’irḥamôu ’ahla l-’arḍi yarḥamoukoum ‘ahlou s-samâ’', 'qui signifient: « Soyez miséricordieux envers les habitants de la terre, les gens du ciel seront alors miséricordieux avec vous ». Cette version explique que ce qui est visé par l’expression (man fi s-samâ’) dans la première version du ḥadīth et dans la ‘āyah: ce sont les anges car ce sont eux les habitants des cieux. En effet, on ne qualifie pas Allāh par l’expression : (’ahlou s-samâ’) « les gens du ciel ». Cette expression concerne bien les anges car ce sont eux les gens des cieux. La règle est que tout verset non explicite qui serait pris selon le sens apparent impliquerait des contradictions dans le Qour’ân alors que le Qour’ân en est absolument exempt. Si ces versets étaient interprétés selon le sens apparent, ils contrediraient d’autres versets non explicites dont le sens apparent donne l’illusion que Allāh serait dans la direction de la terre, comme par exemple Sa parole [sôurat Al-Baqarah / 115] :', 1, 'hadiths, détails, explication, concernant'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« إرحمُو أهلَ الأرضِ يَرحَمُكُم أهلُ السَّماء »');

-- source: https://islam.ms/explication-hadiths-jaria-versets-non-explicites
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Détails et explication concernant hādīth al-jāriyah', NULL, NULL, NULL, '« وَقَالَ إِنِّي ذَاهِبٌ إِلَى رَبِّي سَيَهْدِينِ »', NULL, 'wa qâla ’innî dhâhiboun ’ilâ Rabbî sayahdîn', '[sôurat Aṣ-ṣaffât / 99]. Ce verset relate l’histoire du prophète ’Ibrâhîm qui a dit, lorsqu’il a quitté son peuple qui avait refusé de lui obéir et n’avait pas accepté d’abandonner l’adoration des idoles: (’innî dhâhiboun ‘ilâ Rabbî), c’est à dire vers l’endroit que Allāh m’a facilité à savoir la Palestine où je pourrais adorer Allāh en paix. Ainsi ce verset ne veut pas dire que Allāh se trouverait en Palestine. Ainsi pour le verset:', 1, 'hadiths, détails, explication, concernant'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« وَقَالَ إِنِّي ذَاهِبٌ إِلَى رَبِّي سَيَهْدِينِ »');

-- source: https://islam.ms/explication-hadiths-jaria-versets-non-explicites
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Détails et explication concernant hādīth al-jāriyah', NULL, NULL, NULL, '« فَأَيْنَمَا تُوَلُّواْ فَثَمَّ وَجْهُ اللّهِ »', NULL, 'fa’aynamâ touwallôu fathamma wajhou l-Lâh', 'nous disons : (fathamma qiblatou l-Lâh) comme l’a dit l’un des savants du salaf, Moujāhid, l’élève de ʿAbdoullāh Ibnou ʿAbbās le cousin du prophète, que Allāh les agrée tous les deux: (wajhou l-Lâh) signifie donc: la qibLâh que Dieu agrée pour votre prière surérogatoire lorsque vous êtes en voyage sur une monture. Quant au verset:', 1, 'hadiths, détails, explication, concernant'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« فَأَيْنَمَا تُوَلُّواْ فَثَمَّ وَجْهُ اللّهِ »');

-- source: https://islam.ms/explication-hadiths-jaria-versets-non-explicites
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Détails et explication concernant hādīth al-jāriyah', NULL, NULL, NULL, '« الرَّحْمَنُ عَلَى الْعَرْشِ اسْتَوَى »', NULL, 'Ar-Raḥmânou ʿala l-ʿarchi stawâ', 'istawâ veut dire dominer, préserver, maintenir en existence comme ont dit les savants sunnites tels que al Bayhaqiyy et d’autres. Il faut exempter Allāh de la localisation et de la quantité. Al-Boukhâriyy a rapporté que le Prophète صلى الله عليه وسلم a dit:', 1, 'hadiths, détails, explication, concernant'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« الرَّحْمَنُ عَلَى الْعَرْشِ اسْتَوَى »');

