INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Détails et explication concernant hādīth al-jāriyah', NULL, NULL, NULL, '« قُلْ هَلْ يَسْتَوِي الَّذِينَ يَعْلَمُونَ وَالَّذِينَ لا يَعْلَمُونَ »', 'Dis: Sont-ils équivalents ceux qui ont la science et ceux qui ne l’ont pas ?', 'qoul hal yastawi l-ladhîna yaʿlamôuna wa l-ladhîna lâ yaʿlamôun', 'Et le Messager de Allāh صلى الله عليه وسلم a dit:', 1, 'hadiths, détails, explication, concernant'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« قُلْ هَلْ يَسْتَوِي الَّذِينَ يَعْلَمُونَ وَالَّذِينَ لا يَعْلَمُونَ »');

-- source: https://islam.ms/explication-hadiths-perseverer-adoration
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth: Persévérer sur l’adoration à l’époque des discordes', NULL, NULL, NULL, '« وما تقرّبَ إليَّ عبدي بشيءٍ أَحَبَّ إليَّ ممّا افترضتُ عليه »', 'Mon esclave ne se rapproche pas tant de Mon agrément que par ce que J’ai rendu obligatoire sur lui.', 'wa mâ taqarraba ‘ilayya ʿabdî bichay’in ‘aḥabba ‘ilayya mimma ftaraḍtou ʿalayhi', 'Ce ḥadīth indique l’éminence du mérite qu’il y a à persévérer à accomplir les obligations ; et il n’y a aucun doute que la plus haute et la meilleure des obligations, c’est de croire en Dieu et en Son Messager Le Prophète ṣalla l-Lâhou ʿalayhi wa sallam a dit:', 1, 'hadiths, explication, persévérer, adoration'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« وما تقرّبَ إليَّ عبدي بشيءٍ أَحَبَّ إليَّ ممّا افترضتُ عليه »');

-- source: https://islam.ms/explication-hadiths-perseverer-adoration
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth: Persévérer sur l’adoration à l’époque des discordes', 'Az-Zabîdiyy, dans son commentaire', 'As-Soubkiyy', NULL, '« لقد سألتَ عن عظيمٍ وإنه لَيسيرٌ على مَن يسّره اللهُ تعالى عليه تعبدُ اللهَ لا تُشرِكُ به شيئٌا وتُقيم الصلاةَ وتُؤتي الزكاةَ وتصومُ رمضانَ وتحُجُّ البيتَ إنِ استطعتَ إليه سبيلًا »', 'Tu as demandé là quelque chose de bien éminent, mais néanmoins facile pour celui à qui Allāh le facilite: tu adores Dieu sans rien Lui associer, et tu accomplis la prière, tu t’acquittes de la zakât, tu jeûnes Ramaḍān, et tu fais le pèlerinage à La Mecque si tu en as la capacité.', 'laqad sa’alta ʿan ʿaḍhîmin wa’innahou layacîroun ʿalâ man yassarahou l-Lâhou taʿālā ʿalayh, taʿboudou l-Lâha lâ touchrikou bihî chay’â watouqîmou ṣ-ṣalâta watou’ti z-zakâta wataṣôumou ramaḍâna wataḥoujjou l-bayta ‘ini staṭaʿta ‘ilayhi sabîlâ', 'Ce compagnon éminent Mouʿâdh Ibnou Jabal, qui est connu parmi les compagnons pour son mérite et pour son haut degré, sa persévérance à faire le bien l’avait amené à interroger le Messager de Allāh ṣalla l-Lâhou ʿalayhi wasallam et à lui poser cette question éminente ; et le Messager de Allāh lui a indiqué un grand bien, il lui a ordonné de persévérer sur l’adoration de Dieu, d’être sur l’obéissance à Dieu et de ne rien Lui associer. Il convient de parler, ici, de comment on explique l’adoration, car beaucoup gens ne connaissent pas le sens même de l’adoration. L’adoration, tout comme l’ont expliqué les gens de science, c’est l’extrême limite de la crainte et de la soumission. Cela a été rapporté par Az-Zabîdiyy, dans son commentaire du Qâmôuṣ, le fameux dictionnaire de la langue arabe, d’après As-Soubkiyy, que Allāh lui fasse miséricorde. Celui qui voue son adoration à autre que Dieu ne fait pas partie des musulmans. Allāh ʿazza wajall dit:', 1, 'hadiths, explication, persévérer, adoration'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« لقد سألتَ عن عظيمٍ وإنه لَيسيرٌ على مَن يسّره اللهُ تعالى عليه تعبدُ اللهَ لا تُشرِكُ به شيئٌا وتُقيم الصلاةَ وتُؤتي الزكاةَ وتصومُ رمضانَ وتحُجُّ البيتَ إنِ استطعتَ إليه سبيلًا »');

-- source: https://islam.ms/explication-hadiths-perseverer-adoration
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth: Persévérer sur l’adoration à l’époque des discordes', NULL, NULL, NULL, '« العبادة في الهَرْجِ كهِجْرةٍ إِلي »', 'Persévérer sur l’adoration à l’époque des tueries sera comme faire l’émigration pour me rejoindre.', 'al-ʿibâdatou fi l-harji kahijratin ‘ilayya', 'Félicitation et bonheur à celui qui applique ce à quoi le Prophète honoré ṣalla l-Lâhou ʿalayhi wa sallam nous incite dans ce ḥadīth. Il nous a encouragés dans ce ḥadīth à nous occuper de l’adoration dans les périodes de tueries (harj). Et le (harj) signifie la multiplication des homicides. Et voici que nous vivons dans cette époque de meurtres et de massacres. Nous vivons dans une période de troubles, qui se succèdent comme des pans de murs obscurs. Que chacun d’entre nous s’occupe, dans ces jours-ci, à adorer son Seigneur, pour gagner ce grand mérite. En effet, le Messager a comparé la récompense de celui qui se consacrera à l’adoration durant ces périodes de grand nombre d’homicides, à la récompense de qui a fait l’émigration pour le rejoindre lorsque l’émigration était une obligation. En effet à une époque, l’émigration était obligatoire pour tout musulman qui en était capable. C’était donc un devoir pour toute personne qui pouvait faire l’émigration, d’émigrer pour rejoindre le Messager de Allāh ṣalla l-Lâhou ʿalayhi wa sallam à Médine l’Illuminée. Ensuite ce jugement a été abrogé par révélation après que le Messager de Allāh a conquis La Mecque Honorée. C’est-à-dire qu’après cela l’émigration a cessé d’être obligatoire. Celui qui s’occupe de l’adoration dans une période de grande dissension, de grand nombre d’homicides, de (harj), il aura une récompense semblable à la récompense de ceux qui ont émigré dans la voie que Allāh agrée pour rejoindre le Messager de Allāh ṣalla l-Lâhou ʿalayhi wa sallam. Cela ne veut pas dire qu’il aura une récompense strictement égale à celle des émigrants mais une récompense similaire. Une récompense qui ressemble à la récompense d’un homme ou d’une femme qui a émigré dans le désert, qui a supporté les difficultés du voyage, les douleurs du départ, les épreuves du voyage par obéissance à Allāh taʿālā et à Son Messager. Quel bienfait, quelle récompense et quelle grâce que ce grand mérite qu’obtiendra celui qui se consacrera à l’adoration dans cette époque, et qui aura délaissé ce dont nombre de gens se préoccupent, à savoir la multitude de combats et d’homicides blâmables qui nous ont été interdits. Allāh dit à Son bien-aimé le Prophète élu ṣalla l-Lâhou ʿalayhi wa sallam:', 1, 'hadiths, explication, persévérer, adoration'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« العبادة في الهَرْجِ كهِجْرةٍ إِلي »');

-- source: https://islam.ms/hadiths-fleuve-euphrate-montagne-or-fin-monde
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Signes fin du monde: Le fleuve de l ’Euphrate laissera apparaitre une montagne d’or', NULL, NULL, NULL, 'و في رواية قال : قال رسول الله صلى الله عليه وسلم : "يوشك أن يَحْسِرَ الفرات عن كنز من ذهب، فمن حضره فلا يأخذ منه شيئاً" متفق عليه (أي رَوَاهُ الْبُخَارِيُّ وَ مُسْلِمٌ)', NULL, NULL, 'Et dans une version, ce qui signifie : « De l’Euphrate apparaîtra un trésor d’or, celui [d’entre vous] qui est présent, alors qu’il n’en prenne rien » . Rapporté par Al-Boukhāriyy et Mouslim. Voir aussi: Les Signes de la Fin du Monde (Annonciateurs du Jour du Jugement)', 1, 'hadiths, signes, monde, fleuve'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = 'و في رواية قال : قال رسول الله صلى الله عليه وسلم : "يوشك أن يَحْسِرَ الفرات عن كنز من ذهب، فمن حضره فلا يأخذ منه شيئاً" متفق عليه (أي رَوَاهُ الْبُخَارِيُّ وَ مُسْلِمٌ)');

-- source: https://islam.ms/hadiths-non-explicites
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Les ḥadīth non explicites', NULL, NULL, NULL, 'سَبْعَةٌ يُظِلُّهُمُ اللَّهُ فِي ظِلِّهِ يَوْمَ لاَ ظِلَّ إِلاَّ ظِلُّهُ', 'Il y a sept catégories de personnes que Allāh protègera à l’ombre du Trône, le Jour où il n’y aura pas d’autres ombres que l’ombre du Trône', NULL, 'Al-Boukhāriyy a rapporté que le Messager de Allāh ṣalla l-Lāhou ʿalayhi wa sallam a dit: (sabʿatoun youḍhil-louhoumou l-Lâhou fī ḍhil-lih yawma lâ ḍhilla ‘il-lâ ḍhillouh) Dans ce ḥadīth, il s’agit d’une indication que l’ombre en question correspond à l’ombre d’une chose honorée (at-tachrîf) selon le jugement de Allāh, et il s’agit du Trône. Al-Bayhaqiyy a rapporté dans son livre Al-‘Iʿtiqâd que le Prophète ṣalla l-Lāhou ʿalayhi wa sallam a dit:', 1, 'hadiths, explicites'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = 'سَبْعَةٌ يُظِلُّهُمُ اللَّهُ فِي ظِلِّهِ يَوْمَ لاَ ظِلَّ إِلاَّ ظِلُّهُ');

-- source: https://islam.ms/hadiths-non-explicites
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Les ḥadīth non explicites', NULL, NULL, NULL, 'ما مِنْ قَلْبٍ إِلا بَيْنَ إِصْبِعَيْنِ مِنْ أصَابِعِ الرَّحْمن إنْ شَاءَ أقَامَهُ وَإنْ شَاءَ أزَاغَهُ', 'Il n’y a pas un seul cœur sans qu’il ne soit sous la domination de Allāh, s’Il veut Il le met sur la droiture et s’Il veut Il l’égare', NULL, '(mā min qalbin ‘il-lâ bayna ‘iṣbiʿayni min ‘aṣābiʿi r-raḥmân ‘in châ’a ‘aqâmahou wa ’in châ’a ’azâghahou) Bien sûr, le sens correct qui est conforme avec les expressions utilisées par les arabes, c’est ici le sens de la domination, du fait que les cœurs des gens sont sous la domination de Allāh. Là encore, ce ḥadīth n’est pas à prendre selon le sens apparent. Ceux qui le prennent dans le sens apparent s’imaginent que Allāh aurait deux doigts avec lesquels Il ferait changer le cœur des gens. Al-Boukhâriyy a rapporté que le Prophète ṣalla l-Lāhou ʿalayhi wa sallam a dit:', 1, 'hadiths, explicites'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = 'ما مِنْ قَلْبٍ إِلا بَيْنَ إِصْبِعَيْنِ مِنْ أصَابِعِ الرَّحْمن إنْ شَاءَ أقَامَهُ وَإنْ شَاءَ أزَاغَهُ');

-- source: https://islam.ms/hadiths-non-explicites
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth: yanzilou Rabbounā', NULL, NULL, NULL, '" يَنـزِلُ رَبُّنَا كُلَّ لَيْلَةٍ إِلَى السَّمَاءِ الدُّنْيَا "', NULL, NULL, 'Quant au "nouzoūl" rapporté dans le ḥadîth : (yanzilou Rabbounâ koulla laylatin ’ila s-samâ’i d-dounyâ) cela veut dire que c’est un ange qui descend sur ordre de Dieu pour transmettre de Sa part ce qui signifie : « Qui M’invoque, Je l’exauce, qui Me demande pardon, Je lui pardonne, qui Me demande, Je lui accorde ». L’ange reste le dernier tiers de la nuit dans le ciel de ce bas monde jusqu’à l’aube. Il a été rapporté de l’imam Mâlik qu’il a interprété le ḥadīth par la descente de la miséricorde de Allāh et de Son ordre ou de Ses anges comme on dit dans la langue le sultan a fait telle chose si ses sujets font sur son ordre [dans le livre : charḥ z-Zourqâniyy sur le mouwaṭṭa’ de l’imam Mâlik p34]. Quant à celui qui dit : yanzilou (en gardant le terme en arabe) sans comment, ceci est vrai, car lorsqu’il a dit sans comment, il a nié le mouvement et le déplacement au sujet de Dieu. Ces interprétations correctes ont été rapportés par des grands savants comme an-Nawawiyy dans son commentaire de ṣaḥīḥ Mouslim, ainsi que ibnou Ḥajar al-ʿAsqalâniyy dans son livre fatḥou l-Bârî, commentaire du ṣaḥīḥ al-Boukhâriyy. De plus la version du ḥadîth rapporté par an-Naçâ’iyy qui est ṣaḥīḥ confirme que c’est un ange qui descend sous l’ordre de Dieu :', 1, 'hadiths, explication, yanzilou, rabbounā'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '" يَنـزِلُ رَبُّنَا كُلَّ لَيْلَةٍ إِلَى السَّمَاءِ الدُّنْيَا "');

-- source: https://islam.ms/hadiths-non-explicites
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth: yanzilou Rabbounā', NULL, NULL, NULL, 'إن الله يمهل حتى يمضي شطر الليل الأول فيأمر مناديا فينادي …', 'Quand s’écoule la première moitié de la nuit, Allāh ordonne à un ange qui appelle …', NULL, '(’inna l-Lâha youmhilou ḥattâ yamḍiya chaṭrou l-layli l-’awwal faya’mourou mounâdiyan fayounâdî …) Par ailleurs certains de ceux qui ont rapporté les ḥadîth de Al-Boukhâriyy ont transmis le ḥadîth avec la ḍammah sur le yâ’, c’est-à-dire (younzilou) : Il fait descendre, c’est à dire qu’Il ordonne à un ange de descendre :', 1, 'hadiths, explication, yanzilou, rabbounā'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = 'إن الله يمهل حتى يمضي شطر الليل الأول فيأمر مناديا فينادي …');

-- source: https://islam.ms/hadiths-non-explicites
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth: yanzilou Rabbounā', 'Ibnou Ḥibbān', NULL, NULL, '« يُنزِل ربٌّنا »', 'Allāh fait descendre [un ange] chaque nuit jusqu’au ciel du bas-monde...', NULL, '(’inna l-Lâha younzilou koulla laylatin ’ila s-samâ’i d-dounyâ…) Dans le ḥadīth de al-Jāriyah, le Prophète aurait demandé à la femme: (’ayna l-Lâh), elle aurait répondu: (fi s-samâ’) puis il lui aurait demandé (man ’anâ) « Qui suis-je ? » elle aurait répondu: « Le Messager de Allāh », il aurait alors dit à son maître: ce qui signifie: « Libère-la car elle est croyante ». De plus la version rapportée par Mouslim ne viendrait que d’un seul compagnon. En effet, le ḥadīth de al-Jāriyah donne l’illusion qu’il suffirait que quelqu’un dise: (Allāh fi s-samâ’) pour être jugé croyant alors que ceci est contraire à la vérité. an-Nawawiyy, ar-Rāziyy et d’autres qui ont commenté le livre de Mouslim n’ont pas pris ce ḥadīth selon le sens apparent mais ils ont dit que (‘ayna l-Lâh) vient dans le sens de l’interrogation sur la glorification et l’éminence de Allāh et non pas dans le sens de l’interrogation sur la localisation dans l’espace. Voir: L’Imam An-Nawawiyy explique le ḥadīth al-Jâriyah (ḥadīth de la femme esclave) En effet on dit dans la langue arabe (‘ayna foulân –‘ayna Untel– ?) dans le sens de quel degré a-t-il ? Quelle est l’élévation de son mérite ? D’autre part, lorsque l’on dit (fi s-samâ’), cela peut signifier, dans la langue arabe, la supériorité du mérite. C’est de cette manière que les deux savants du ḥadīth, an-Nawawiyy et ar-Râziyy, l’ont interprété: ils ne l’ont pas pris selon le sens apparent comme l’ont fait les assimilationnistes. Le ḥadīth a effectivement été rapporté par l’Imam Mouslim tel que nous l’avons cité mais il a aussi été rapporté dans les termes: (Qui est ton Seigneur ?) auxquels elle aurait répondu: « Allāh » [rapporté par Ibnou Ḥibbān], de même que par les termes: (’ayna l-Lâh) après lesquels elle aurait pointé le doigt vers le ciel [rapporté par al-Bayhaqiyy]. Il a enfin été rapporté dans les termes:', 1, 'hadiths, explication, yanzilou, rabbounā'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« يُنزِل ربٌّنا »');

-- source: https://islam.ms/hadiths-non-explicites
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Conclusion', NULL, NULL, NULL, 'وَمَنْ وَصَفَ اللهَ بِمَعْنًى مِنْ مَعَانِي البَشَر فَقَدْ كَفَر', 'Et celui qui attribue à Allāh un des attributs des humains il devient mécréant', NULL, '(wa man waṣafa l-Lâha bi maʿnan min maʿâni l-bachar faqad kafar) Parmi les attributs des humains, il y a les organes, les mouvements, les changements d’humeurs, la localisation, la forme, la couleur. Allāh est exempt d’une totale exemption de toute ressemblance avec les attributs des humains Après ces quelques rappels, notre conseil pour vous, si vous lisez une ‘āyah dans le Qour’ân ou un ḥadīth, dont le sens apparent serait contraire aux ‘âyah explicites, ne vous précipitez pas si vous n’avez jamais entendu l’explication de la part de ceux qui sont qualifiés pour le faire, dites : « ce texte a un sens qui est digne de Allāh » et référez-vous aux ‘āyah explicites. Ne retenez pas le sens apparent, un sens qui conduirait à penser que Allāh aurait des similitudes avec les choses qu’Il a créées. Suivez la parole de l’Imam Aḥmad Ar-Rifaʿiyy, lui qui a vécu dans le sixième siècle de l’Hégire et qui était le savant de son époque, il était Mouḥaddith [spécialiste du ḥadīth] et Moufassir [spécialiste de l’exégèse du Qour’ân], il a dit dans son livre Al-Bourhânou l-Mou’ayyad au sujet des termes suivants qui font partie de ce qui n’est pas explicite dans la langue arabe : fawq, yad, ʿayn, sāq, nouzôul : « Tout ceci est bien parvenu dans le Livre et la Sounnah avec un sens apparent indiquant ce qui a été cité, mais il est également parvenu dans le Livre et la Sounnah ce qui est semblable et qui en explique le sens visé ».', 1, 'hadiths, conclusion, explicites'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = 'وَمَنْ وَصَفَ اللهَ بِمَعْنًى مِنْ مَعَانِي البَشَر فَقَدْ كَفَر');

-- source: https://islam.ms/hadiths-profite-cinq-choses-avant-cinq-autres
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'hadiths: Profite de cinq choses avant cinq autres', NULL, NULL, NULL, '« اغتنم خمسا قبل خمسا اغتنم حياتك قبل موتك وصحتك قبل سقمك وشبابك قبل هرمك وغناك قبل فقرك وفراغك قبل شغلك »', 'Profites de cinq choses avant cinq autres: profite de ta vie avant ta mort, de ta bonne santé avant ta maladie, de ta jeunesse avant ta vieillesse, de ta richesse avant ta pauvreté, et de ton temps libre avant d’être occupé', NULL, 'Certes la personne raisonnable est celle qui s’occupe de ce que comporte ce ḥadīth. A savoir accomplir le bien et obéir à Allāh tabâraka wa taʿālā, apprendre ce qui est licite et ce qui est interdit, puis mettre en pratique ce que l’on a appris en accomplissant les devoirs et en évitant les péchés. Cela sera une grande provision dans la deuxième vie, la vie qui commence après la mort. Celui qui aura accompli ce qui lui sera profitable après la mort, il ne le regrettera pas dans l’au-delà. Celui également qui aura tiré bénéfice de sa santé avant d’être atteint par la maladie, il aura rassemblé énormément de bien, du bien qu’il ne sera plus en mesure d’accomplir quand il sera touché par la maladie car la maladie empêche la personne de réaliser tout ce qu’elle aurait souhaité. Celui qui est raisonnable profite également de sa jeunesse avant sa vieillesse. Il ne convient pas à celui qui est jeune d’être insouciant par rapport à ce qu’il pourrait faire pour son au-delà, avant que la vieillesse ne l’atteigne. Il convient également à celui qui est raisonnable de profiter de sa richesse en effectuant des bonnes œuvres avant d’être atteint par la pauvreté. La personne qui est pourvue d’argent peut œuvrer pour l’au-delà en réalisant de nombreuses choses. Elle peut dépenser pour les pauvres et les miséreux. Elle pourra aussi entretenir les liens avec ses proches parents en agissant envers eux avec générosité. Dans ce cas où elle ne ferait rien de tout cela, elle le regretterait si elle tombait un jour dans la pauvreté. Il convient aussi que le musulman profite en multipliant les actes de bien quand il dispose de temps libre et ce, avant qu’il ne soit accaparé par diverses occupations, de ce qu’il occuperait au détriment de ce qui lui sera profitable dans l’au-delà. De nombreuses personnes ne profitent pas comme il se doit de ces cinq bienfaits. Parmi elles, se trouvent celles qui n’y prêtent pas attention et ne s’en rendent compte qu’une fois qu’elles sont mortes, tout comme l’a dit notre maître ʿAliyy, que Allāh l’agrée: " Les gens sont endormis et c’est quand ils meurent qu’ils se réveillent ". Cela veut dire que la plupart des gens sont comme endormis, c’est-à-dire qu’ils sont insouciants et ils délaissent ce qui leur sera bénéfique après la mort. Seulement après la mort, ils en prendront connaissance et regretteront. Que l’on sache que la meilleure des œuvres, selon le jugement de Allāh, c’est de croire en Allāh et en Son Messager. Nous demandons à Allāh taʿālā qu’Il nous fasse apprendre ce que nous ignorons, qu’Il fasse que nous profitions de ce que nous avons appris et qu’Il nous augmente en connaissance.', 1, 'hadiths, profite'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« اغتنم خمسا قبل خمسا اغتنم حياتك قبل موتك وصحتك قبل سقمك وشبابك قبل هرمك وغناك قبل فقرك وفراغك قبل شغلك »');

-- source: https://islam.ms/hadiths-regarder-droite-gauche-priere
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'hadiths sur le fait de jeter des regards à droite et à gauche dans la prière', NULL, NULL, NULL, 'عن عائشة قالت : سألت رسول الله صلى الله عليه وسلم عن الالتفات في الصلاة فقال : « هو اختلاس (الأخذ بسرعة على غفلة) يختلسه الشيطان من صلاة العبد » رَوَاهُ البخاري', NULL, NULL, 'D’après notre dame ʿA’ichah, que Dieu l’agrée, elle a dit: J’ai demandé au Messager de Dieu, que Dieu l’élève davantage en degrés, sur le fait de jeter des regards [à droite et à gauche] durant la prière, il a dit ce qui signifie: « C’est une prise [rapide, faite à la personne qui est insouciante à ce moment-là] par le diable, qu’il prend durant la prière de la personne ». Rapporté par Al-Boukhâriyy. Et aussi:', 1, 'hadiths, jeter, regards, droite'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = 'عن عائشة قالت : سألت رسول الله صلى الله عليه وسلم عن الالتفات في الصلاة فقال : « هو اختلاس (الأخذ بسرعة على غفلة) يختلسه الشيطان من صلاة العبد » رَوَاهُ البخاري');

-- source: https://islam.ms/hadiths-regarder-droite-gauche-priere
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'hadiths sur le fait de jeter des regards à droite et à gauche dans la prière', NULL, NULL, NULL, 'عن أنس قال : قال لي رسول الله صلى الله عليه وسلم : « إياك والالتفات في الصلاة فإن الالتفات في الصلاة هلكة ، فإن كان لا بد ففي التطوع لا في الفريضة » رَوَاهُ الترمذي أي سبب الهلاك و ذلك لأن ارتكاب المكروهات قد يؤدي إلى ارتكاب المحرمات فيكون أهلك نفسه بتعريضها للعقاب', NULL, NULL, 'Selon Anas, que Dieu l’agrée, il a dit: Le Messager de Dieu, que Dieu l’élève davantage en degrés, m’a dit ce qui signifie: « Gare à toi au fait de jeter des regards [à droite ou à gauche], durant la prière, car jeter des regards durant la prière [peut-être une cause qui] mène à la perte. Si c’est vraiment nécessaire [que tu regardes], alors seulement durant les [prières] surérogatoires, mais pas durant les [prières] obligatoires ». Rapporté par at-Tirmîdhiyy. C’est-à-dire que la personne qui fait les choses déconseillées, cela peut la mener à faire des choses interdites, alors elle aura mené sa personne à sa perte, en l’exposant au châtiment.', 1, 'hadiths, jeter, regards, droite'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = 'عن أنس قال : قال لي رسول الله صلى الله عليه وسلم : « إياك والالتفات في الصلاة فإن الالتفات في الصلاة هلكة ، فإن كان لا بد ففي التطوع لا في الفريضة » رَوَاهُ الترمذي أي سبب الهلاك و ذلك لأن ارتكاب المكروهات قد يؤدي إلى ارتكاب المحرمات فيكون أهلك نفسه بتعريضها للعقاب');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« مَنْ نَفَّسَ عَنْ مُؤْمِنٍ كُرْبَةً مِنْ كُرَبِ الدُّنْيا نَفَّسَ اللهُ عَنْهُ كُرْبَةً مِنْ كُرَبِ يَوْمِ القِيامَة، ومَنْ يَسَّرَ عَلى مُعْسِرٍ يَسَّرَ اللهُ عَلَيْهِ في الدُّنْيا والآخِرَةِ ومَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللهُ في الدُّنْيا والآخِرَةِ واللهُ في عَوْنِ العَبْدِ ما كانَ العَبْدُ في عَوْنِ أَخِيهِ ومَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللهُ بِهِ طَرِيقًا إِلى الجَنَّةِ وما اجْتَمَعَ قَوْمٌ في بَيْتٍ مِنْ بُيُوتِ اللهِ يَتْلُونَ كِتابَ اللهِ ويَتَدارَسُونَهُ بَيْنَهُمْ إِلاَّ نَزَلَتْ عَلَيْهِمُ السَّكِينَةُ وغَشِيَتْهُمُ الرَّحْمَةُ وحَفَّتْهُمُ الْمَلائِكَةُ وذَكَرَهُمُ اللهُ فِيمَنْ عِنْدَهُ ومَنْ بَطَّأَ بِهِ عَمَلُهُ لَمْ يُسْرِعْ بِهِ نَسَبُهُ »', 'celui qui soulage un croyant d’un des tourments du bas monde, Allāh le soulage d’un des tourments du Jour du Jugement, celui qui facilite pour quelqu’un qui est dans la difficulté, Allāh lui facilite dans le bas monde et dans l’au-delà, celui qui ne dévoile pas un musulman, Allāh ne le dévoile pas dans le bas monde et dans l’au-delà, Allāh aide l’esclave tant que l’esclave aide son frère, et celui qui suit un chemin par lequel il recherche d’acquérir une science, Allāh lui facilite grâce à ce chemin un chemin pour le Paradis, et toutes les fois que des gens se réunissent dans une des mosquées pour réciter le Livre de Allāh et pour l’étudier entre eux, alors la sérénité descend sur eux, la miséricorde les enveloppe, et les anges les entourent et Allāh fait qu’ils soient mentionnés par les anges des plus hauts degrés, et celui qui n’œuvre pas suffisamment, son ascendance ne va pas lui compenser son manquement.', NULL, 'La parole du Prophète:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« مَنْ نَفَّسَ عَنْ مُؤْمِنٍ كُرْبَةً مِنْ كُرَبِ الدُّنْيا نَفَّسَ اللهُ عَنْهُ كُرْبَةً مِنْ كُرَبِ يَوْمِ القِيامَة، ومَنْ يَسَّرَ عَلى مُعْسِرٍ يَسَّرَ اللهُ عَلَيْهِ في الدُّنْيا والآخِرَةِ ومَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللهُ في الدُّنْيا والآخِرَةِ واللهُ في عَوْنِ العَبْدِ ما كانَ العَبْدُ في عَوْنِ أَخِيهِ ومَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللهُ بِهِ طَرِيقًا إِلى الجَنَّةِ وما اجْتَمَعَ قَوْمٌ في بَيْتٍ مِنْ بُيُوتِ اللهِ يَتْلُونَ كِتابَ اللهِ ويَتَدارَسُونَهُ بَيْنَهُمْ إِلاَّ نَزَلَتْ عَلَيْهِمُ السَّكِينَةُ وغَشِيَتْهُمُ الرَّحْمَةُ وحَفَّتْهُمُ الْمَلائِكَةُ وذَكَرَهُمُ اللهُ فِيمَنْ عِنْدَهُ ومَنْ بَطَّأَ بِهِ عَمَلُهُ لَمْ يُسْرِعْ بِهِ نَسَبُهُ »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« مَنْ نَفَّسَ عَنْ مُؤْمِنٍ كُرْبَةً مِنْ كُرَبِ الدُّنْيا نَفَّسَ اللهُ عَنْهُ كُرْبَةً مِنْ كُرَبِ يَوْمِ القِيامَة »', NULL, NULL, 'qui signifie: « celui qui soulage un croyant d’un des tourments du bas monde, Allāh le soulage d’un des tourments du Jour du Jugement.» Ceci est dû au fait que la rétribution est de la même catégorie que l’acte qui a été fait. Il y a eu beaucoup de textes à ce sujet, comme le ḥadīth:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« مَنْ نَفَّسَ عَنْ مُؤْمِنٍ كُرْبَةً مِنْ كُرَبِ الدُّنْيا نَفَّسَ اللهُ عَنْهُ كُرْبَةً مِنْ كُرَبِ يَوْمِ القِيامَة »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', 'Al-Boukhâriyy', NULL, NULL, '« إِنَّما يَرْحَمُ اللهُ مِنْ عِبادِهِ الرُّحَماءَ »', NULL, NULL, 'qui signifie: « Allāh fait miséricorde à Ses esclaves qui sont miséricordieux » [rapporté par Al-Boukhâriyy] Et le ḥadīth:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« إِنَّما يَرْحَمُ اللهُ مِنْ عِبادِهِ الرُّحَماءَ »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', 'Mouslim', NULL, NULL, '« إِنَّ اللهَ يُعَذِّبُ الَّذِينَ يُعَذِّبُونَ الناسَ في الدُّنْيا »', NULL, NULL, 'qui signifie: « Certes Allāh châtie ceux qui châtient les gens dans le bas monde » [rapporté par Mouslim] Ici le tourment fait référence à la grande difficulté qui entraîne la personne dans un grand tourment. Et soulager une personne d’un tourment c’est alléger son tourment et le délivrer d’un tourment c’est plus que cela, c’est le fait de le décharger du tourment de sorte qu’il n’ait plus aucun souci. La rétribution du soulagement est un soulagement, et la rétribution de la délivrance est une délivrance. Al-Bayhaqiyy a rapporté du ḥadīth de ’Anas, attribué au Prophète:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« إِنَّ اللهَ يُعَذِّبُ الَّذِينَ يُعَذِّبُونَ الناسَ في الدُّنْيا »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« أَنَّ رَجُلاً مِنْ أَهْلِ الجَنَّةِ يُشْرِفُ يَوْمَ القِيامَةِ عَلى أَهْلِ النارِ، فَيُنادِيهِ رَجُلٌ مِنَ النارِ يا فُلانُ هَلْ تَعْرِفُنِي ؟ فَيَقُولُ لا واللهِ ما أَعْرِفُكَ مَنْ أَنْتَ ؟ فَيَقُولُ أَنا الَّذِي مَرَرْتَ بِهِ في دارِ الدُّنْيا فَٱسْتَسْقَيْتَنِي شُرْبَةً مِنْ ماءٍ فَسَقَيْتُكَ قالَ عَرَفْتُ. فَقالَ فَٱشْفَعْ لي بِها عِنْدَ رَبِّكَ، فَقالَ فَيَسْأَلُ اللهَ تَعالى فَيَقُولُ شَفِّعْنِي فِيهِ فَيُشَفَّعُ فِيهِ فَيَأْمُرُ بِهِ فَيُخْرَجُ مِنَ النار»', 'qu’un homme des gens du Paradis va regarder au Jour du jugement les gens de l’enfer. C’est alors qu’un de ceux de l’enfer l’appelle et lui dit " Ô untel me reconnais-tu?" il lui répond "non par Allāh, je ne te connais pas qui es-tu?" il lui dit "moi je suis celui auprès de qui tu es passé dans le bas monde et à qui tu as demandé une gorgée d’eau et je te l’ai donnée" alors il lui répond "oui je t’ai reconnu" alors il lui dit "intercède en ma faveur en mentionnant cette gorgée d’eau [afin que Ton Seigneur me délivre du feu]" il a dit : alors il demande à Allāh taʿālā, en disant "laisse-moi intercéder en sa faveur" et Il le laisse intercéder en sa faveur et Il ordonne qu’on le fasse sortir de l’enfer', NULL, 'Fin de citation Le Prophète a mentionné les tourments du jour dernier par sa parole:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« أَنَّ رَجُلاً مِنْ أَهْلِ الجَنَّةِ يُشْرِفُ يَوْمَ القِيامَةِ عَلى أَهْلِ النارِ، فَيُنادِيهِ رَجُلٌ مِنَ النارِ يا فُلانُ هَلْ تَعْرِفُنِي ؟ فَيَقُولُ لا واللهِ ما أَعْرِفُكَ مَنْ أَنْتَ ؟ فَيَقُولُ أَنا الَّذِي مَرَرْتَ بِهِ في دارِ الدُّنْيا فَٱسْتَسْقَيْتَنِي شُرْبَةً مِنْ ماءٍ فَسَقَيْتُكَ قالَ عَرَفْتُ. فَقالَ فَٱشْفَعْ لي بِها عِنْدَ رَبِّكَ، فَقالَ فَيَسْأَلُ اللهَ تَعالى فَيَقُولُ شَفِّعْنِي فِيهِ فَيُشَفَّعُ فِيهِ فَيَأْمُرُ بِهِ فَيُخْرَجُ مِنَ النار»');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« كُرْبَةً مِنْ كُرَبِ يَوْمِ القِيامَة »', NULL, NULL, 'qui signifie: « d’un des tourments du Jour du Jugement » car les tourments du bas monde sont comme rien du tout par rapport aux tourments de l’au-delà. Ainsi Al-Boukhâriyy a rapporté de Abôu Hourayrah, que Allāh l’agréé, que le Messager de Allāh a dit:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« كُرْبَةً مِنْ كُرَبِ يَوْمِ القِيامَة »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, 'Al-Maqdâd ibnou l-Aswad qu’il a', NULL, '« يَعْرَقُ الناسُ يَوْمَ القِيامَةِ حَتَّى يَذْهَبَ عَرَقُهُمْ في الأَرْضِ سَبْعِينَ ذِراعًا، ويُلْجِمُهُمْ حَتَّى يَبْلُغَ ءاذانهم »', 'les gens au Jour du Jugement vont transpirer au point que leur transpiration va atteindre 70 coudées sur terre et elle va atteindre leur bouche et leurs oreilles', NULL, 'Et dans Mouslim d’après Al-Maqdâd ibnou l-Aswad qu’il a dit:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« يَعْرَقُ الناسُ يَوْمَ القِيامَةِ حَتَّى يَذْهَبَ عَرَقُهُمْ في الأَرْضِ سَبْعِينَ ذِراعًا، ويُلْجِمُهُمْ حَتَّى يَبْلُغَ ءاذانهم »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« تُدْنَى الشَّمْسُ يَوْمَ القِيامَةِ مِنَ الخَلْقِ حَتَّى تَكُونَ مَنْهُمْ كَمِقْدارِ مِيلٍ فَيَكُونُ الناسُ عَلى قَدْرِ أَعْمالِهِمْ في العَرَقِ فَمِنْهُمْ مَنْ يَكُونُ إِلى كَعْبَيْهِ ومِنْهُمْ مَنْ يَكُونُ إِلى رُكْبَتَيْهِ ومِنْهُمْ مَنْ يَكُونُ إِلى حَقْوَيْهِ ومِنْهُمْ مَنْ يُلْجِمُهُ العَرَقُ إِلْجامًا »', 'j’ai entendu le Messager de Allāh dire ce qui signifie le soleil se rapproche au Jour du Jugement des créatures au point qu’elles se trouvent à une distance de un mile. Les gens seront dans un état qui est relatif à leurs actes, il y a certains d’entre eux dont la transpiration va arriver jusqu’aux chevilles, d’autres jusqu’aux genoux, d’autres jusqu’au niveau des reins, et d’autres seront bridés par la transpiration jusqu’à la bouche', NULL, 'et le Messager a montré sa bouche Sa parole:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« تُدْنَى الشَّمْسُ يَوْمَ القِيامَةِ مِنَ الخَلْقِ حَتَّى تَكُونَ مَنْهُمْ كَمِقْدارِ مِيلٍ فَيَكُونُ الناسُ عَلى قَدْرِ أَعْمالِهِمْ في العَرَقِ فَمِنْهُمْ مَنْ يَكُونُ إِلى كَعْبَيْهِ ومِنْهُمْ مَنْ يَكُونُ إِلى رُكْبَتَيْهِ ومِنْهُمْ مَنْ يَكُونُ إِلى حَقْوَيْهِ ومِنْهُمْ مَنْ يُلْجِمُهُ العَرَقُ إِلْجامًا »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« كانَ تاجِرٌ يُدايِنُ الناسَ فَإِذا رَأَى مُعْسِرًا قالَ لِفِتْيانِهِ تَجاوَزُوا عَنْهُ لَعَلَّ اللهَ يَتَجاوَزُ عَنّا فَتَجاوَزَ اللهُ عَنْهُ »', 'il y avait un commerçant, il prêtait de l’argent aux gens, et lorsqu’il voyait que quelqu’un était dans la difficulté il disait à ses serviteurs facilitez lui, puisse Allāh nous faciliter, et Allāh lui a accordé cela.', NULL, 'Al-Boukhâriyy et Mouslim rapportent également de HouDHayfah et Abôu Masʿôud, que Allāh les agréé tous les deux, que le Messager de Allāh a dit:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« كانَ تاجِرٌ يُدايِنُ الناسَ فَإِذا رَأَى مُعْسِرًا قالَ لِفِتْيانِهِ تَجاوَزُوا عَنْهُ لَعَلَّ اللهَ يَتَجاوَزُ عَنّا فَتَجاوَزَ اللهُ عَنْهُ »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« ماتَ رَجُلٌ فَقِيلَ لَهُ بِمَ غَفَرَ اللهُ لَكَ ؟ فَقالَ كُنْتُ أُبايِعُ الناسَ فَأَتَجَوَّزُ عَنِ الْمُوسِرِ وأُخَفِّفُ عَنِ الْمُعْسِرِ »', 'un homme est mort et il lui a été dit "quelle était la cause par laquelle il t’a été pardonné" il a répondu "j’étais un commerçant je vendais aux gens, je facilitais à celui qui était dans l’aisance et j’allégeais à celui qui est dans la difficulté.', NULL, 'Et dans le Mousnad de Ibnou ʿOumar, que Allāh l’agréé, il est cité que le Prophète a dit:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« ماتَ رَجُلٌ فَقِيلَ لَهُ بِمَ غَفَرَ اللهُ لَكَ ؟ فَقالَ كُنْتُ أُبايِعُ الناسَ فَأَتَجَوَّزُ عَنِ الْمُوسِرِ وأُخَفِّفُ عَنِ الْمُعْسِرِ »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« مَنْ أَرادَ أَنْ تُسْتَجابَ دَعْوَتُهُ وأَنْ تُكْشَفَ كُرْبَتُهُ فَلْيُفَرِّجْ عَنْ مُعْسِرٍ »', 'celui qui veut que son invocation soit exaucée et qu’il soit délivré de ses tourments, alors qu’il délivre quelqu’un qui est dans la difficulté.', NULL, 'Et parmi ce qui est conforme au ḥadīth du Prophète:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« مَنْ أَرادَ أَنْ تُسْتَجابَ دَعْوَتُهُ وأَنْ تُكْشَفَ كُرْبَتُهُ فَلْيُفَرِّجْ عَنْ مُعْسِرٍ »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« وَمَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللهُ في الدُّنْيا وَالآخِرَةِ »', NULL, NULL, 'qui signifie: « celui qui ne dévoile pas un musulman, Allāh ne le dévoile pas dans le bas monde et dans l’au-delà. » Il y a ce qui a été rapporté d’un des Salaf qui a dit " j’ai vu des gens qui n’avaient pas de défaut mais ils ont mentionné les défauts des gens, les gens leur ont à leur tour mentionné des défauts, et j’ai vu des gens qui avaient des défauts, ils se sont abstenus de mentionner les défauts des gens, c’est alors qu’à notre tour nous avons oublié leurs défauts" fin de citation. Ibnou Mâjah a rapporté du Prophète qu’il a dit:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« وَمَنْ سَتَرَ مُسْلِمًا سَتَرَهُ اللهُ في الدُّنْيا وَالآخِرَةِ »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« وَاللهُ في عَوْنِ العَبْدِ ما كانَ العَبْدُ في عَوْنِ أَخِيهِ »', NULL, NULL, 'qui signifie: « Allāh aide l’esclave tant que l’esclave aide son frère », at-Tabarâniyy a rapporté du ḥadīth de ʿOumar, marfôuʿ, attribué au Prophète:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« وَاللهُ في عَوْنِ العَبْدِ ما كانَ العَبْدُ في عَوْنِ أَخِيهِ »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« أَفْضَلُ الأَعْمالِ إِدْخالُ السُّرُورِ عَلَى الْمُؤْمِنِ، كَسَوْتَ عَوْرَتَهُ أَوْ أَشْبَعْتَ جَوْعَتَهُ أَوْ قَضَيْتَ حاجَتَهُ »', 'Parmi les meilleures des œuvres c’est d’introduire la joie dans le cœur d’un croyant, que ce soit en lui donnant de quoi se vêtir ou en remplissant son estomac ou en lui réglant son affaire', NULL, 'Et ʿOumar s’occupait des veuves, il leur amenait de l’eau la nuit. Il est arrivé que Ṭalḥah a vu ʿOumar, la nuit, renter dans la maison d’une femme, c’est alors que Ṭalḥah a rendu visite à cette femme pendant le jour. Il vit que c’était une vieille femme aveugle, handicapée, et il l’a interrogé "que venait faire cet homme chez toi?" Elle a dit " mais il le fait depuis tant (et elle a cité une longue période), il s’occupait de moi, il me ramenait ce qui me permet de rester en vie et il fait évacuer ce qui est nuisible" Ṭalḥah a dit: « Ô Ṭalḥah tu recherches les défauts de ʿOumar ?!! » Il y avait beaucoup de vertueux qui proposaient à leurs compagnons d’être à leur service. Un homme a tenu la compagnie à un groupe dans la conquête dans la voie agrée par Allāh, et il leur a mis comme condition d’être à leur service et chaque fois que l’un d’entre eux voulait se laver la tête ou son vêtement, il se levait et il le faisait pour eux. Et lorsqu’il mourut, ils l’ont dévoilé pour le ghousl, ils ont vu sur sa main inscrit (en arabe) "au nombre des gens du Paradis" et ils ont vu que c’était une écriture entre la peau et la chair. Quant à la parole du Prophète:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« أَفْضَلُ الأَعْمالِ إِدْخالُ السُّرُورِ عَلَى الْمُؤْمِنِ، كَسَوْتَ عَوْرَتَهُ أَوْ أَشْبَعْتَ جَوْعَتَهُ أَوْ قَضَيْتَ حاجَتَهُ »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« ومَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللهُ لَهُ بِهِ طَرِيقًا إِلى الجَنَّة »', NULL, NULL, 'qui signifie: « Celui qui prend une voie par laquelle il recherche une science, Allāh lui facilite une voie pour le Paradis » Ici, la voie pour quérir une science concerne aussi bien le sens propre du terme, c’est-à-dire de marcher avec ses pieds et ce qui est de cet ordre, et aussi le sens figuré, comme ceux qui mémorisent la science, qui l’étudient, qui la révisent, qui l’écrivent et ce qui est de cet ordre. Il se peut que ce qui est visé du ḥadīth soit que Allāh lui facilite la science qu’il recherche et lui facilite le moyen pour y arriver – et la science de la religion est un moyen qui mène au Paradis. Il se peut aussi que le sens visé soit que Allāh facilite à celui qui recherche la science avec sincérité le chemin pour être sur la bonne guidée, la voie qui mène au Paradis. Sa recherche de la science serait donc une cause pour sa bonne guidée et son entrée au Paradis. Celui donc qui suit le chemin de la science et qui n’en dévie pas, arrivera au Paradis par le plus simple et le plus proche des chemins. Il n’y a pas une voie pour connaître Allāh et avoir Son agrément par autre que celle de la science utile que Allāh a envoyé par Ses prophètes et descendue dans Ses livres [célestes]. Concernant la parole du Prophète:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« ومَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللهُ لَهُ بِهِ طَرِيقًا إِلى الجَنَّة »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« ما جَلَسَ قَوْمٌ في بَيْتٍ مِنْ بُيُوتِ اللهِ يَتْلُونَ كِتابَ اللهِ ويَتَدارَسُونَهُ بَيْنَهُمْ إِلاَّ نَزَلَتْ عَلَيْهِمُ السَّكِينَةُ وغَشِيَتْهُمُ الرَّحْمَةُ وحَفَّتْهُمُ الْمَلائِكَةُ وذَكَرَهُمُ اللهُ فِيمَنْ عِنْدَهُ »', NULL, NULL, 'qui signifie: « Il n’y a pas des gens qui s’assoient dans une assemblée dans une mosquée et qui récitent le Livre de Allāh et qui l’étudient entre eux sans que la sérénité ne descende sur eux, que la miséricorde ne les enveloppe, et les anges les entourent et Allāh fait qu’ils soient mentionnés par les anges des plus hauts degrés » Ce ḥadīth indique le caractère recommandé de prendre place dans la mosquée pour la récitation du Qour’ân et son étude. Et si on explique ce ḥadīth par le fait d’apprendre le Qour’ân et l’enseigner, il n’y a pas de divergence sur le fait que c’est recommandé. Et dans Al-Boukhâriyy, le Prophète a dit:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« ما جَلَسَ قَوْمٌ في بَيْتٍ مِنْ بُيُوتِ اللهِ يَتْلُونَ كِتابَ اللهِ ويَتَدارَسُونَهُ بَيْنَهُمْ إِلاَّ نَزَلَتْ عَلَيْهِمُ السَّكِينَةُ وغَشِيَتْهُمُ الرَّحْمَةُ وحَفَّتْهُمُ الْمَلائِكَةُ وذَكَرَهُمُ اللهُ فِيمَنْ عِنْدَهُ »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« خَيْرُكُمْ مَنْ تَعَلَّمَ القُرْءانَ وعَلَّمَهُ »', 'Font partie des meilleurs d’entre vous ceux qui apprennent le Qour’ân et qui l’enseignent', NULL, 'Abôu Saʿîd Al-Khoudriyy, que Allāh l’agréé, a rapporté que le Prophète a dit:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« خَيْرُكُمْ مَنْ تَعَلَّمَ القُرْءانَ وعَلَّمَهُ »');

-- source: https://islam.ms/hadiths-soulager-croyant-musulman-epreuve-toument
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explication du ḥadīth au sujet de celui qui soulage un croyant d’un tourment.', NULL, NULL, NULL, '« ما مِنْ قَوْمٍ صَلُّوا صَلاةَ الغَداةِ ثُمَّ قَعَدُوا في مُصَلاّهُمْ يَتَعاطَوْنَ كِتابَ اللهِ ويَتَدارَسُونَهُ إِلاَّ وَكَّلَ اللهُ بِهِمْ مَلائِكَةً يَسْتَغْفِرُونَ لَهُمْ حَتَّى يَخُوضُوا في حَدِيثٍ غَيْرِهِ »', 'chaque fois qu’il y a des personnes qui font la prière du milieu de la journée puis sont restés dans leur lieu de prière à évoquer le Livre de Allāh, à le réviser, alors Allāh charge pour eux des anges qui demandent le pardon en leur faveur jusqu’à ce qu’ils discutent d’autre chose', NULL, 'Et dans le ṣaḥīḥ de Mouslim, le Messager de Allāh est sorti un jour et il a vu une assemblée de ses compagnons, il a dit:', 1, 'hadiths, explication, sujet, celui'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« ما مِنْ قَوْمٍ صَلُّوا صَلاةَ الغَداةِ ثُمَّ قَعَدُوا في مُصَلاّهُمْ يَتَعاطَوْنَ كِتابَ اللهِ ويَتَدارَسُونَهُ إِلاَّ وَكَّلَ اللهُ بِهِمْ مَلائِكَةً يَسْتَغْفِرُونَ لَهُمْ حَتَّى يَخُوضُوا في حَدِيثٍ غَيْرِهِ »');

-- source: https://islam.ms/histoire-nourrisson-parle-hadiths-apparences-vertu
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Le nourrisson qui parla : Un récit prophétique sur les apparences et la piété', NULL, NULL, NULL, 'ليس أمرًا عاديًا أن نرى طفلًا رضيعًا يتكلّم بكلام مفهم فصيح، ولكنَّ الله عزَّ وجلَّ يُظهِر بعض العجائب ليعتبر الناس ويتفكّروا ويتدبّروا، ومن هذه العجائب ما جرى مع إحدى الأمّهات التي كانت ترضع ولدها فحدثت أمامهما حادثة أخبرنا عنها النبيُّ الأعظم ﷺ وقد وقعت في إحدى الأمم السابقة.', NULL, NULL, 'Il n''est guère habituel de voir un nourrisson parler d''un langage compréhensible et clair. Cependant, Allāh ʿazza wa jall manifeste des choses étonnantes afin que les gens en tirent des leçons, y réfléchissent et y méditent. Et il y a parmi ces faits hors du commun, une histoire que le Prophète éminent ṣalla I-Lāhouʿalayhi wa sallam nous rapporta, ayant eu lieu dans l''une des communautés antérieures.', 1, 'hadiths, nourrisson, parla, récit'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = 'ليس أمرًا عاديًا أن نرى طفلًا رضيعًا يتكلّم بكلام مفهم فصيح، ولكنَّ الله عزَّ وجلَّ يُظهِر بعض العجائب ليعتبر الناس ويتفكّروا ويتدبّروا، ومن هذه العجائب ما جرى مع إحدى الأمّهات التي كانت ترضع ولدها فحدثت أمامهما حادثة أخبرنا عنها النبيُّ الأعظم ﷺ وقد وقعت في إحدى الأمم السابقة.');

-- source: https://islam.ms/histoire-nourrisson-parle-hadiths-apparences-vertu
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Le nourrisson qui parla : Un récit prophétique sur les apparences et la piété', NULL, NULL, NULL, 'ثم سألت ولدها عن الشابّة التي كانت تُضرب فقال الطفل الرضيع: إن الشابّة كانت صالحة تقيّة، وقد افترى عليها بعض الناس زورًا وبهتانًا فصبرت وقالت: «حسبي الله ونعم الوكيل»، فدعوتُ الله أن يجعلني مثلها أي صابرًا محتسبًا، إن المغزى من هذه القصة أنّ بعض الناس قد يطلبون ما فيه مضرّتهم، والمطلوب ترك التكبّر والظلم كما أن المطلوب الصبر على الشدائد.', NULL, NULL, 'La mère interrogea ensuite son enfant à propos de la jeune femme qui s’était faite frapper et de son invocation. Il lui répondit : « Cette jeune femme est vertueuse, une pieuse et à cause des calomnies de certains, elle a subi cette injustice mais elle a patienté et a dit : « Ḥasbiyā l-Lahou wa niʿma l-wakīl. » J’ai donc invoqué Allah pour qu’il fasse que je sois comme elle, une personne qui patiente en espérant la récompense de la part de Allāh. » La morale de cette histoire est qu’il est possible que certaines personnes demandent une chose qui leur est nuisible en réalité mais dans tous les cas, il est toujours requis de délaisser l’orgueil et l’injustice, et de patienter face aux épreuves.', 1, 'hadiths, nourrisson, parla, récit'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = 'ثم سألت ولدها عن الشابّة التي كانت تُضرب فقال الطفل الرضيع: إن الشابّة كانت صالحة تقيّة، وقد افترى عليها بعض الناس زورًا وبهتانًا فصبرت وقالت: «حسبي الله ونعم الوكيل»، فدعوتُ الله أن يجعلني مثلها أي صابرًا محتسبًا، إن المغزى من هذه القصة أنّ بعض الناس قد يطلبون ما فيه مضرّتهم، والمطلوب ترك التكبّر والظلم كما أن المطلوب الصبر على الشدائد.');

-- source: https://islam.ms/interpretation-exegese-correcte-coran-qouran-hadiths
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Le grand savant Badrou d-dîn ibnou jamâʿah (728 h) explique le sens du ḥadîth an-Nouzoūl', NULL, NULL, NULL, '« مَهْمَا تَصَوَّرْتَ بِباَلِكَ فَالله بِخِلافِ ذَالِك »', 'Quoi que tu imagines, Allāh en est différent', 'mahmā taṣawwarta bibālika fa l-Lāhou bikhilāfi dhālik', 'Le président des juges châfiʿiyy en Égypte à son époque, Badrou d-dîn ibnou jamâʿah (décédé en 728 h) a dit dans son livre : Iḍâḥou d-dalîl fî qaṭʿi ḥoujaji ’ahli t-taʿṭîl page 164 : « sache qu’il n’est pas permis de donner le sens du déplacement de haut en bas [à Dieu] dans le ḥadîth du nouzôul, et ceci pour plusieurs raisons : - La première : la descente est un attribut des corps et de ce qui entrent en existence, elle requiert trois choses : un espace de déplacement, un espace qui est quitté et un espace qui est atteint, et tout cela est impossible s’agissant de Allāh. - La seconde : si la descente était une réalité pour Allāh, il se renouvellerait pour Lui chaque jour et chaque nuit beaucoup de mouvements qui L’occuperaient entièrement toute la nuit, de même que beaucoup de déplacements. En effet, le tiers de la nuit se renouvelle pour les gens de la terre au fur et à mesure à chaque moment, cela impliquerait son déplacement dans le ciel du bas-monde nuit et jour, d’un peuple à l’autre, son retour vers le Trône à chaque instant selon leurs dires, et sa descente à chaque instant dans le ciel du bas-monde. Et cela, quelqu’un doué d’un minimum d’intelligence et d’entendement ne le dit pas. - La troisième : à celui qui dit que Allāh est sur le Trône, et qu’Il le remplit ; comment le ciel du bas-monde pourrait-il Le contenir alors que ce ciel est par rapport au Trône comme un anneau dans une terre déserte ? Selon vos dires, il ne resterait que deux solutions : soit l’agrandissement du ciel du bas-monde à chaque moment pour Le contenir, soit la réduction de l’être glorifié (Qui est absolument exempt de cela) jusqu’à rentrer dedans. Quant à nous, les gens de Ahlou s-Sounnah, nous sommes formels à nier les deux cas.» fin de citation. Remarque : Il est recommandé que la personne accomplisse dans le dernier tiers de la nuit beaucoup d’invocations et des prières surérogatoires. Le tiers de la nuit est calculé depuis le couché jusqu’à l’aube divisé par trois, la dernière partie étant le dernier tiers de la nuit. Par exemple en se levant une heure avant l’aube, la personne est dans le dernier tiers de la nuit. Allāh n’a pas besoin des créatures. Il n’a nul besoin d’autrui, de toute éternité alors que toutes les créatures ont besoin de Lui. Allāh n’a pas besoin de l’endroit. Il n’est pas localisé dans un endroit ni dans une direction, car Il existe taʿālā de toute éternité avant l’endroit sans endroit, et c’est Lui Qui a créé l’endroit, Il n’a donc nul besoin de l’endroit. Par ailleurs, l’objectif de l’Ascension (Al-Miʿrâj) n’est pas de faire parvenir le Prophète à un endroit où serait localisé Allāh. L’objectif est plutôt d’honorer davantage le Prophète en lui montrant les choses extraordinaires qui sont dans les mondes célestes, c’est de glorifier son degré et de lui accorder la vision de Allāh par le cœur sans que Allāh soit localisé dans l’espace et les directions. Le Calife bien guidé l’Imâm ʿAliyy Ibnou Abî Ṭâlib que Allāh l’honore, a dit : « Dieu existe de toute éternité alors qu’aucun endroit n’est de toute éternité et Il est maintenant tel qu’Il est de toute éternité – c’est-à-dire sans endroit – ». Ce dont on tient compte dans la croyance n’est pas basé sur les illusions mais sur la raison saine qui est témoin de la religion, car si Allāh était dans un endroit, Il aurait des limites, des extrémités, des fins et celui qui est ainsi a forcément une existence précédée du néant c’est-à-dire qu’Il est créé et n’est donc pas Dieu. Comme il a été validé que Allāh existe sans endroit avant la création des endroits et des directions, il est validé qu’Il existe après les avoir créés sans endroit. Et ceci ne constitue pas une négation de l’existence de Allāh Taʿâlâ. L’Imam Aḥmad ibnou Ḥanbal, ainsi que l’imam Dhou n-Nôun Al-Miṣriyy [élève de l’imam Mâlik] ont dit : [rapporté par le Ḥâfidh ’Abôu Bakr l-khaṭîb al-Baghdâdiyy dans son livre târikhou baghdâd avec une chaîne de transmission remontant jusqu’à Dhou n-Nôun Al-Miṣriyy et rapporté aussi par ’Abôu l-Faḍl At-Tamîmiyy Al-Ḥanbaliyy dans son livre ’iʿtiqâdou l-’imâm ’Aḥmad], ainsi il est impossible d’imaginer le Créateur car Il ne ressemble pas aux créatures Quant au Ḥadîth de Zaynab Bintou Jaḥch, la femme du Prophète ṣalla l-Lâhou ʿalayhi wa sallam dans lequel elle disait : "زَوَّجَكُنَّ أَهَالِيكُنَّ وَزَوَّجَنِيَ اللهُ مِنْ فَوْقِ سَبْعِ سَمَوَاتٍ" (zawwajakounna ‘ahâlîkounna wa zawwajaniya l-Lâhou min fawqi sabʿi samâwât) ce qui signifie : "[Ô femmes] ce sont vos familles qui vous ont mariées alors que moi, c’est Allāh qui m’a mariée, mon mariage était inscrit au-dessus des sept cieux". Ceci signifie que le mariage du Prophète avec elle est inscrit dans la Table Préservée de façon spécifique (à savoir sans témoins ni tuteur), la table préservée étant au-dessus des sept cieux. Al-Ḥâfiḍh Ibnou Ḥajar a dit dans Fatḥou l-Bâriy, Al-Karmaniy a dit: « sa parole fi s-samâ’, le sens apparent n’est pas visé car Allāh est exempt d’être localisé dans un endroit et ainsi ont répondu d’autres que lui concernant les termes de al-fawqiyyah et ce qui est du même genre ». Chihābou d-dîn al-Qasṭalâniyy dans son commentaire qui s’appelle irchâdou s-sârī charḥ ṣaḥīḥ Al-Boukhâriyy a dit pour le commentaire de ce ḥadîth : « sa parole " inna l-Lâha ’ankaḥanî fi s-samâ’ : Allāh est exempt des endroits et de la direction. Ce qui est visé par sa parole fi s-samâ’, l’indication de l’éminence de Allāh et de Ses attributs et cela ne vise pas que Allāh serait localisé dans le ciel, Allāh est totalement exempt de cela ». An-Naçā’iyy a rapporté le ḥadîth avec le terme inna l-Lâha ʿazza wa jall ’ankaḥanî mina s-samâ’ ". L’imam as-sindiyy a dit dans son commentaire de as-sounan (de an-Naçā’iyy) : « sa parole " ’ankaḥanî mina s-samâ’ " c’est-à-dire que Dieu a révélé Sa parole zawwajanâkahâ [sôurat Al-’Aḥzab ’âyah 37]» Voir aussi : Les Règles d’Interprétations du Qour’ân et du ḥadīth. Exégèse Correcte du Coran', 1, 'hadiths, grand, savant, badrou'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« مَهْمَا تَصَوَّرْتَ بِباَلِكَ فَالله بِخِلافِ ذَالِك »');

-- source: https://islam.ms/invocation-ablution
INSERT INTO "douaa" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Invocation après les ablutions', 'أَشْهَدُ أَنْ لاَ إلهَ إلاَّ اللَّهُ وَحْدَهُ لاَ شَرِيكَ لَهُ', '', '', 'Voici ce qu’on dit après avoir fait les [petites] ablutions - le wouḍou’ - :', '', 'invocation, ablutions, wouḍou'
WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = 'أَشْهَدُ أَنْ لاَ إلهَ إلاَّ اللَّهُ وَحْدَهُ لاَ شَرِيكَ لَهُ');

-- source: https://islam.ms/invocation-ablution
INSERT INTO "douaa" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Invocation après les ablutions', 'وَأَشْهَدُ أَنَّ مُحَمَّداً عَبْدُهُ وَرَسُولُهُ', '', '', '', '', 'invocation, ablutions, wouḍou'
WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = 'وَأَشْهَدُ أَنَّ مُحَمَّداً عَبْدُهُ وَرَسُولُهُ');

-- source: https://islam.ms/invocation-apres-fajr-maghrib
INSERT INTO "douaa" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Invocation après la prière de al-fajr et de al-maghrib', 'لا إلهَ إلا اللهُ وَحْدَهُ لا شَرِيكَ لَهُ ، لَهُ المُلْكُ وَ لَهُ الحَمْدُ', '', '', 'Il est parvenu que celui qui dit après la prière de al-fajr et après la prière de al-maghrib:', '', 'invocation, prière, al-fajr, al-maghrib'
WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = 'لا إلهَ إلا اللهُ وَحْدَهُ لا شَرِيكَ لَهُ ، لَهُ المُلْكُ وَ لَهُ الحَمْدُ');

-- source: https://islam.ms/invocation-apres-fajr-maghrib
INSERT INTO "douaa" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Invocation après la prière de al-fajr et de al-maghrib', 'يُحْيِي وَ يُمِيتُ وَهُوَ عَلَى كُلِّ شيء قَدِير', 'Il n’est de dieu que Allāh, Celui Qui est unique et Qui n’a pas d’associé, à Lui la souveraineté et à Lui la louange, Il fait vivre et Il fait mourir, et Il est sur toute chose tout-puissant', 'lā ’ilāha ’il-la l-Lāhou wahdahou lā charīka lah lahou l-moulkou wa lahou l-ḥamdou youḥyī wa youmīt wa houwa ʿalā koulli chay’in qadīr', 'Il dit dix fois cette invocation (après avoir passé le salam dans la prière), avant qu’il ne change de position (qu’il avait lorsqu’il a terminé sa prière), il lui sera écrit dix bonnes actions particulières, il lui sera effacé dix mauvaises actions parmi les grands péchés, il sera protégé contre les mauvaises choses, il sera parmi ceux qui seront en sécurité et qui seront apaisés, et il sera préservé contre le chayṭān et contre la nuisance des jinn et il sera préservé de la nuisance de la sorcellerie.', '', 'invocation, prière, al-fajr, al-maghrib'
WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = 'يُحْيِي وَ يُمِيتُ وَهُوَ عَلَى كُلِّ شيء قَدِير');

-- source: https://islam.ms/invocation-apres-priere
INSERT INTO "douaa" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Invocations que l’on dit après chacune des cinq prières', 'اللَّهُمَّ أعِنِّي على ذِكْرِكَ وَشُكْرِكَ وحُسْنِ عِبادَتِكَ', 'Ô Allāh aide moi à T’évoquer, à Te remercier et à accomplir les actes d’adoration que Tu agrée', 'Allāhoumma ’aʿinnī ʿalā dhikrika wa choukrika wa ḥousni ʿibādatik', '', '', 'invocation, invocations, chacune, prières'
WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = 'اللَّهُمَّ أعِنِّي على ذِكْرِكَ وَشُكْرِكَ وحُسْنِ عِبادَتِكَ');

-- source: https://islam.ms/invocation-apres-priere
INSERT INTO "douaa" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Invocations que l’on dit après chacune des cinq prières', 'اللَّهُمَ أَنْتَ السَّلام وَمِنْكَ السَّلام تَبَارَكْتَ يَا ذَا الجَلالِ وَالإكْرَام', 'Ô Allāh tu es As-Salām [- Celui Qui est exempt de tout défaut -] et c’est Toi Qui accorde la sauvegarde, Tu es exempt d’imperfection Ô Toi Dhou l-Jalāli wa l-’Ikrām [- Celui Qui mérite d’être glorifié et Qui mérite de ne pas être renié, et Il est Celui Qui accorde aux saints la réussite au Jour du Jugement -]', 'Allāhoumma ’anta s-salāmou wa minka s-salām tabārakta yā dha l-jalāli wa l-’ikrām', 'Aboū Hourayrah, que Allāh l’agrée, rapporte que le Prophète ṣalla l-Lāhou ʿalayhi wa sallam a dit:', '', 'invocation, invocations, chacune, prières'
WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = 'اللَّهُمَ أَنْتَ السَّلام وَمِنْكَ السَّلام تَبَارَكْتَ يَا ذَا الجَلالِ وَالإكْرَام');

-- source: https://islam.ms/invocation-apres-priere
INSERT INTO "douaa" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Invocations que l’on dit après chacune des cinq prières', 'مَنْ سَبَّحَ اللَّهَ فِي دُبُرِ كُلِّ صَلاةٍ ثَلاثًا وَثَلاثِينَ وَحَمِدَ اللَّهَ ثَلاثًا وَثَلاثِينَ وَكَبَّرَ اللَّهَ ثَلاثًا وَثَلاثِينَ فَتْلِكَ تِسْعَةٌ وَتِسْعُونَ وَقَالَ تَمَامَ الْمِائَةِ : لا إِلَهَ إِلاّ اللَّهُ وَحْدَهُ لا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ غُفِرَتْ خَطَايَاهُ وَإِنْ كَانَتْ مِثْلَ زَبَدِ الْبَحْرِ', 'Celui qui dit après chaque prière (soubḥāna l-Lāh) 33 fois, (al-ḥamdou li l-Lāh) 33 fois, (Allāhou ’akbar) 33 fois, soit 99 évocations en tout, et pour la 100ème évocation, il dit: (lā ’ilāha il-la l-Lāhou waḥdahou lā charīka lah, lahou l-moulkou wa lahou l-ḥamdou, wa houwa ʿalā koulli chay’in qadīr), il lui sera pardonné ses péchés même s’ils étaient aussi nombreux que les écumes de la mer', '', '[rapporté par Mouslim]', '', 'invocation, invocations, chacune, prières'
WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = 'مَنْ سَبَّحَ اللَّهَ فِي دُبُرِ كُلِّ صَلاةٍ ثَلاثًا وَثَلاثِينَ وَحَمِدَ اللَّهَ ثَلاثًا وَثَلاثِينَ وَكَبَّرَ اللَّهَ ثَلاثًا وَثَلاثِينَ فَتْلِكَ تِسْعَةٌ وَتِسْعُونَ وَقَالَ تَمَامَ الْمِائَةِ : لا إِلَهَ إِلاّ اللَّهُ وَحْدَهُ لا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ غُفِرَتْ خَطَايَاهُ وَإِنْ كَانَتْ مِثْلَ زَبَدِ الْبَحْرِ');

-- source: https://islam.ms/invocation-apres-priere-soubh-maghrib
INSERT INTO "douaa" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Invocations après la prière de aṣ-ṣoubḥ et de al-maghrib', 'اللَّهُمَّ أجِرْنِي مِنَ النَّارِ', 'Ô Allāh préserve moi du feu de l’enfer', 'Allāhoumma ’ajirnī mina n-nār', 'Il a été rapporté dans le ḥadith que le croyant qui dit cette invocation sept fois après la prière de aṣ-ṣoubḥ, s’il meurt durant la journée, Allāh le préserve du feu de l’enfer. Et s’il dit cette invocation sept fois après la prière de al-maghrib, s’il meurt durant la nuit, Allāh le préserve du feu de l’enfer. L’invocation qu’on répète sept fois est la suivante:', '', 'invocation, invocations, prière, aṣ-ṣoubḥ'
WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = 'اللَّهُمَّ أجِرْنِي مِنَ النَّارِ');

-- source: https://islam.ms/invocation-assemble-science
INSERT INTO "douaa" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Invocation lors des assemblées de science', 'إِنَّ النَّاسَ إِذا اجْتَمَعُوا فِي مَجْلِس ثُمَّ فَارَقُوهُ وَلَمْ يَذْكُرُوا اللهَ', '', '', 'Le Messager de Allāh ṣalla l-Lāhou ʿalayhi wa sallam a dit:', '', 'invocation, lors, assemblées, science'
WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = 'إِنَّ النَّاسَ إِذا اجْتَمَعُوا فِي مَجْلِس ثُمَّ فَارَقُوهُ وَلَمْ يَذْكُرُوا اللهَ');

-- source: https://islam.ms/invocation-assemble-science
INSERT INTO "douaa" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Invocation lors des assemblées de science', 'وَلَمْ يُصَلُّوا عَلَى النَّبِي يَكُونُ حَسْرَةً عَلَيْهِم فِي الآخِرَةِ وَإِن دَخَلُوا الجَنَّة', 'Lorsque des croyants se réunissent dans une assemblée de science et qu’ils se séparent sans avoir évoqué Allāh et sans avoir fait l’invocation en faveur du Prophète, ils manqueront d’un bien dans l’au-delà, même s’ils entrent au Paradis', '’inna n-nāça ’idha jtamaʿoū fī majlis thoumma fāraqoūhou wa lam yadhkoūrou l-Lāha wa lam youṣallou ʿala n-nabiyy yakoūnou ḥasratan ʿalayhim fi l-’ākhirati wa ’in dakhalou l-jannah', '[rapporté par Aṭ-Ṭabarāniyy dans son livre Ad-Daʿawat] Dans l’au-delà, la personne dira: « si seulement je n’avais pas raté ce bien ». Même si elle entre au Paradis, elle dira cela sans en ressentir de tristesse. Lorsqu’elle verra l’éminente récompense de l’évocation de Allāh et de l’invocation en faveur du Prophète ṣalla l-Lāhou ʿalayhi wa sallam, elle dira: « si seulement je n’avais pas raté cette récompense ». On peut donc dire après une assemblée de science ( et on peut répéter chacune de ces invocations trois fois ):', '', 'invocation, lors, assemblées, science'
WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = 'وَلَمْ يُصَلُّوا عَلَى النَّبِي يَكُونُ حَسْرَةً عَلَيْهِم فِي الآخِرَةِ وَإِن دَخَلُوا الجَنَّة');

