WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = 'اللَّهُمَّ صَلِّ عَلَى سَيِّدِنَا مُحَمَّدٍ وَ عَلَى آلِهِ وَ صَحْبِهِ وَ سَلِّم');

