WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = 'الصَّلاةُ وَالسَّلامُ عَلَيكَ يَا سَيِّدِي يَا رَسُولَ اللهَ يَا أَحْمَد قَلَّتْ حِيلَتِي وَأَنتَ وَسِيلَتِي فَأَدْرِكْنِي (21 مرات)');

