INSERT INTO "douaa" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Dieu fait changer les créatures et Lui ne change pas', '« قال لي يا محمد إني إذا قضيت قضاء فإنه لا يرد »', 'Il m’a dit: Ô Mouḥammad, ce que je prédestine ne sera pas changée', 'Qâla lî yâ Mouḥammad ’Innî ’idhâ qaḍaytou qaḍâ’an fa’innahou lâ youradd', 'Alors mieux que le douʿâ’ cité précédemment qui comprend ces mauvaises paroles, il y a cette invocation même si elle n’a pas été rapportée du Messager de Allāh, qui est la suivante:', '', 'invocation, dieu, changer, créatures'
WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = '« قال لي يا محمد إني إذا قضيت قضاء فإنه لا يرد »');

-- source: https://islam.ms/nuit-15-chabane-invocation
INSERT INTO "douaa" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Dieu fait changer les créatures et Lui ne change pas', 'اللّهمّ يا الله يا الله يا الله يا حيّ يا قيّوم يا غفور يا توّاب يا فتّاح يا رزّاق يا واسع يا معين يا باسط يا مبدئ يا وهّاب يا متين ويا حافظ يا وليّ يا كافي يا حسيب يا أرحم الرّاحمين يا ذا المنّ ويا ذا الفضل ويا ذا الجلال والإكرام ويا ذا الطّول والإنعام ويا من تمحو ما تشاء وتثبت ما تشاء ويا من عندك أمّ الكتاب بحقّ أسماءك الحسنى وآياتك العظمى وبحقّ اسمك العظيم الأعظم وبالتجلّي في ليلة النّصف من شعبان المكرّم صلّ على سيّدنا ومولانا وحبيبنا وشفيعنا وملاذنا محمّد رسولك ونبيّك الأكرم صلاة كاملة دائمة تكتبنا بها عندك في هذه اللّيلة المباركة مغفورين لهم مسعودين معمّرين بالخير مرزوقين موفّقين للأذكار والطّاعات والخيرات والحسنات ومستغنين بفضلك في الدّارين عمّن سواك وصلّ على سيّدنا محمّد صلاة تكتبنا بها في هذه اللّيلة من السّعداء والصّالحين وترزقنا بها في الدّارين إيمانا كاملا وكمال اليقين بحقّ سيّدنا محمّد سيّد المرسلين وإمام المتّقين ومحبوب ربّ العالمين وتكشف بها عنا البليات والآفات والعاهات الواردة بإرادتك هذه السّنة لتصيب بها من تشاء من عبادك إنّك مجيب الدّعوات وما ذلك على الله بعزيز وصلّى الله على سيّدنا محمّد وعلى آله وصحبه وسلّم.', '', '', 'Allāhoumma yâ Allāhou yâ Allāhou yâ Allāh yâ Ḥayyou yâ Qayyôumou yâ Ghafôurou yâ Tawwâbou yâ Fattâḥou yâ Razzâqou yâ Wâçiʿou yâ Mouʿîn yâ Bâciṭou yâ Moubdi’ou yâ Wahhâbou yâ Matînou wa yâ Ḥâfiḍhou yâ Waliyyou yâ Kâfî yâ Ḥacîb yâ ’Arḥama r-Râḥimîn yâ Dha l-Manni wa yâ Dha l-Faḍl wa yâ Dha l-Jalâli wa l-’Ikrâm wa yâ Dha ṭ-Ṭawli wa l-’Inʿâm wa yâ man tamḥou mâ tachâ’ wa touthbitou mâ tachâ’ou liman tachâ’ wa yâ man ʿindaka ’oummou l-kitâb biḥaqqi ’asmâ’ika l-Ḥousnâ wa ’âyâtika l-ʿouḍhmâ wa biḥaqqi ismika l-ʿaḍhîmi l-’aʿḍham wa bi t-tajallî fî laylati n-niṣfi min chaʿbâni l-moukarram ṣalli ʿalâ sayyidinâ wa mawlânâ wa ḥabîbinâ wa chafîʿinâ wa malâdhinâ Mouḥammad raçôulika wa nabiyyika l-’akram ṣalâtan kâmilatan dâ’imatan taktoubounâ bihâ ʿindaka fî hâdhihi l-laylati l-moubârakah maghfôurîna lahoum masʿôudîna mouʿammirîna bi l-khayr marzôuqîna mouwaffaqîna li l-’adhkâri wa ṭ-ṭâʿâti wa l-khayrâti wa l-ḥaçanât wa moustaghnîna bifaḍlika fi d-dârayn ʿamman siwâk, wa ṣalli ʿalâ sayyidinâ Mouḥammad ṣalâtan taktoubounā bihâ fī hâdhihi l-laylati mina s-souʿadâ’i wa ṣ-ṣāliḥîn wa tarzouqounâ bihâ fi d-dârayni ’Imânan kâmilan wa kamâla l-yaqîn biḥaqqi sayyidinâ Mouḥammadin sayyidi l-mourçalîn wa ’imâmi l-mouttaqîn wa maḥbôubi Rabbi l-ʿâlamîn wa takchifou bihâ ʿanna l-baliyyâti wa l-’âfâti wa l-ʿâhâti l-wâridah bi’irâdatika hâdhihi s-sanata litouṣîba bihâ man tachâ’ou min ʿibâdika ’innaka Moujîbou d-daʿawâti wa mâ dhâlika ʿala l-Lâhi bi ʿazîz, wa ṣalla l-Lâhou ʿalâ sayyidinâ Mouḥammad wa ʿalâ ’âlihi wa ṣaḥbihi wa sallam.', '', 'invocation, dieu, changer, créatures'
WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = 'اللّهمّ يا الله يا الله يا الله يا حيّ يا قيّوم يا غفور يا توّاب يا فتّاح يا رزّاق يا واسع يا معين يا باسط يا مبدئ يا وهّاب يا متين ويا حافظ يا وليّ يا كافي يا حسيب يا أرحم الرّاحمين يا ذا المنّ ويا ذا الفضل ويا ذا الجلال والإكرام ويا ذا الطّول والإنعام ويا من تمحو ما تشاء وتثبت ما تشاء ويا من عندك أمّ الكتاب بحقّ أسماءك الحسنى وآياتك العظمى وبحقّ اسمك العظيم الأعظم وبالتجلّي في ليلة النّصف من شعبان المكرّم صلّ على سيّدنا ومولانا وحبيبنا وشفيعنا وملاذنا محمّد رسولك ونبيّك الأكرم صلاة كاملة دائمة تكتبنا بها عندك في هذه اللّيلة المباركة مغفورين لهم مسعودين معمّرين بالخير مرزوقين موفّقين للأذكار والطّاعات والخيرات والحسنات ومستغنين بفضلك في الدّارين عمّن سواك وصلّ على سيّدنا محمّد صلاة تكتبنا بها في هذه اللّيلة من السّعداء والصّالحين وترزقنا بها في الدّارين إيمانا كاملا وكمال اليقين بحقّ سيّدنا محمّد سيّد المرسلين وإمام المتّقين ومحبوب ربّ العالمين وتكشف بها عنا البليات والآفات والعاهات الواردة بإرادتك هذه السّنة لتصيب بها من تشاء من عبادك إنّك مجيب الدّعوات وما ذلك على الله بعزيز وصلّى الله على سيّدنا محمّد وعلى آله وصحبه وسلّم.');

-- source: https://islam.ms/preuve-permis-invocation-faveur-prophete-apres-appel-priere
INSERT INTO "douaa" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Quelle est la preuve qu’il est permis de faire l’invocation en faveur du Prophète après l’appel à la prière ?', '« إِذَا سَمِعْتُمُ المُؤَذِّنَ فَقُولُوا كَمَا يَقُولُ ثُمَّ صَلُّوا عَلَيَّ »', 'Lorsque vous entendez le mou’adh-dhin, répétez ce qu’il dit, ensuite faites l’invocation en ma faveur', '’idhā samiʿtoumou l-mou’adh-dhina faqoūlou kamā yaqoūlou thoumma ṣalloū ʿalayy', '[rapporté par Mouslim]. Il y a également le ḥadīth :', '', 'invocation, quelle, preuve, permis'
WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = '« إِذَا سَمِعْتُمُ المُؤَذِّنَ فَقُولُوا كَمَا يَقُولُ ثُمَّ صَلُّوا عَلَيَّ »');

-- source: https://islam.ms/preuve-permis-invocation-faveur-prophete-apres-appel-priere
INSERT INTO "douaa" (sujet, texte_arabe, texte_francais, phonétique, explication, commentaire, tag)
SELECT 'Quelle est la preuve qu’il est permis de faire l’invocation en faveur du Prophète après l’appel à la prière ?', '« مَن ذَكَرَنِي فَلْيُصَلِّ عَلَيَّ »', 'Que celui qui cite mon nom invoque en ma faveur pour que Allāh m’honore davantage', 'man dhakarani fa l-youṣalli ʿalayy', '[rapporté par le ḥāfiḍh As-Sakhāwiyy]. Vous pouvez écouter ou télécharger l’audio du ’Adhān fait par le récitateur égyptien connu ʿAbdou l-Bāsiṭ ʿabdou ṣ-Ṣamad à la fin du ’Adhān il fait l’invocation en faveur du prophète:', '', 'invocation, quelle, preuve, permis'
WHERE NOT EXISTS (SELECT 1 FROM "douaa" WHERE texte_arabe = '« مَن ذَكَرَنِي فَلْيُصَلِّ عَلَيَّ »');

-- source: https://islam.ms/rattraper-jeune-rompu-ramadan
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'hadiths Bienfait de l’Argent Licite Halal pour l’Homme Vertueux', NULL, NULL, NULL, '« إِنَّ هَذا المالَ حُلْوَةٌ خَضِرَةٌ مَنْ أَخَذَهُ بِحَقِّهِ ووَضَعَهُ في حَقِّهِ فَنِعْمَ الْمَعُونَةُ هُوَ ومَنْ أَخَذَهُ بِغَيْرِ حَقِّهِ كانَ كَالَّذِي يَأْكُلُ ولا يَشْبَعُ »', 'Certes, ces biens [matériels] sont comme des fruits frais qui sont doux et plaisants, celui qui obtient les biens justement et qui les utilise justement, quelle bonne aide que sont ces biens. Et celui qui les obtient injustement est semblable à celui qui mange et qui n’est jamais rassasié.', '‘inna hâdha l-mâla Houlwatoun khaDirah man ‘akhadhahou biHaqqihî wa waDaʿahôu fî Haqqihî faniʿma l-maʿôunatou houwa wa man ‘akhadhahou bighayri Haqqihî kâna kalladhî ya’koulou wa lâ yachbaʿ', 'Le Messager de Allāh a comparé l’argent du point de vue du désir de l’obtenir et du penchant et de l’attachement de l’âme à l’avoir, aux fruits qui sont frais, bons et sucrés, que l’âme désire et pour lesquels elle penche. Celui qui obtient son argent d’une voie licite et qui l’utilise dans des voies licites – il va alors l’utiliser comme moyen pour combler ses besoins et ceux de sa famille et l’utiliser dans les voies de bienfaisance et de bien avec l’intention de se préserver ou bien il va l’utiliser pour son épouse, avec une bonne intention, ou ses enfants ou ses parents ou ses proches parents – il s’agit alors d’un immense bienfait de la part de Allāh pour son esclave croyant. L’argent, si le croyant l’obtient d’une voie que Allāh a rendue licite et qu’il l’utilise dans ce que Allāh agrée, ce sera une aide pour son au-delà car il sera une cause pour gagner des récompenses dans l’au-delà. Ce sera donc une bonne aide pour ce qui est de son intérêt au jour du jugement tout comme il est une aide pour ce qui est de son intérêt dans la vie d’ici-bas. Quant à celui qui l’obtient injustement et l’a donc acquis d’une voie interdite, il sera privé de cette bénédiction, il sera semblable à celui qui mange et qui n’est jamais rassasié, même s’il dispose de beaucoup d’argent et il sera chargé de ses péchés au jour du jugement. L’argent, chers frères de foi, n’est pas dans tous les cas blâmé. En effet, le Prophète a dit:', 1, 'hadiths, bienfait, argent, licite'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« إِنَّ هَذا المالَ حُلْوَةٌ خَضِرَةٌ مَنْ أَخَذَهُ بِحَقِّهِ ووَضَعَهُ في حَقِّهِ فَنِعْمَ الْمَعُونَةُ هُوَ ومَنْ أَخَذَهُ بِغَيْرِ حَقِّهِ كانَ كَالَّذِي يَأْكُلُ ولا يَشْبَعُ »');

-- source: https://islam.ms/rattraper-jeune-rompu-ramadan
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'hadiths Bienfait de l’Argent Licite Halal pour l’Homme Vertueux', NULL, NULL, NULL, '« نِعْمَ الْمالُ الصّالِحُ لِلرَّجُلِ الصّالِحِ »', 'Quel bienfait que l’argent licite pour l’homme vertueux !', 'niʿma l-mâlou S-SâliH lir-rajouli S-SâliH', 'L’homme vertueux qui obtient son argent d’une voie licite et qui le dépense dans les voies de bien, quel bienfait que cet argent pour lui ! Nous avons en la personne du Messager de Allāh et en ses compagnons, que Allāh les agrée, un excellent exemple dans la manière d’utiliser l’argent dans les voies de bien et de bienfaisance. Ibnou ʿAbbâs, que Allāh les agrée lui et son père a dit: « Le Messager de Allāh était le plus généreux des gens et il était encore plus généreux durant le mois de Ramaḍān lorsqu’il rencontrait Jibrîl ʿalayhi s-salâm. Ainsi, le Messager de Allāh à ce moment-là devenait plus généreux pour diffuser le bien que le vent envoyé pour cela. » Abôu Bakr, que Allāh l’agrée était un exemple pour dépenser et donner dans l’obéissance à Allāh taʿālā. Il a ainsi dépensé toute sa richesse dans la voie que Allāh ʿazza wa jall agrée tout cela par recherche de l’au-delà et pour soutenir la religion agrée par Allāh et pour aider le Messager de Allāh, pour soutenir les musulmans qui étaient démunis. Au point que le Messager de Allāh a dit:', 1, 'hadiths, bienfait, argent, licite'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« نِعْمَ الْمالُ الصّالِحُ لِلرَّجُلِ الصّالِحِ »');

-- source: https://islam.ms/rattraper-jeune-rompu-ramadan
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'hadiths Bienfait de l’Argent Licite Halal pour l’Homme Vertueux', NULL, NULL, NULL, '« ما نَفَعَنِي مالٌ قَطُّ ما نَفَعَنِي مالُ أَبِي بَكْرٍ »', 'Aucun bien ne m’a été autant utile que le bien de Abôu Bakr !', NULL, 'C’est alors que Abôu Bakr que Allāh l’agrée se mit à pleurer et il dit: « Ne suis-je moi-même et mes biens que pour toi ô Messager de Dieu. » ʿOumar que Allāh l’agrée a dit: « le Messager de Allāh nous a ordonné de faire des aumônes et cela a coïncidé un jour où j’avais un certain bien. Je me suis dit c’est aujourd’hui l’occasion où je pourrais faire mieux que Abôu Bakr si je pouvais faire mieux que lui un jour. J’ai alors amené la moitié de ce que je possédais. Le Messager de Allāh m’a dit:', 1, 'hadiths, bienfait, argent, licite'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« ما نَفَعَنِي مالٌ قَطُّ ما نَفَعَنِي مالُ أَبِي بَكْرٍ »');

-- source: https://islam.ms/rattraper-jeune-rompu-ramadan
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'hadiths Bienfait de l’Argent Licite Halal pour l’Homme Vertueux', NULL, NULL, NULL, '« مَا أَبْقَيْتَ لأَهْلِكَ »', 'Qu’est ce que tu as laissé pour ta famille ?', NULL, 'Je lui ai dit: « Pareil à ce que je viens de donner. » C’est alors que Abôu Bakr vint avec tout ce qu’il possédait. Et le Messager de Allāh lui dit:', 1, 'hadiths, bienfait, argent, licite'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« مَا أَبْقَيْتَ لأَهْلِكَ »');

-- source: https://islam.ms/regles-interpretations-qouraan-hadiths
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Fakhr d-dîn ar-Râzî explique le sens de istawā', NULL, NULL, NULL, 'وَهَذَا لِسَانٌ عَرَبِيٌّ مُّبِينٌ', 'Et ceci (la révélation) est une langue arabe claire', 'wa hâdha liçânoun ʿarabiyyoun moubîn', '[sourat An-Naḥl / ‘ayah 103] On comprend de cette ‘âyah qu’une des bases essentielles pour la bonne compréhension du Qour’ān, c’est bien sûr la connaissance de la langue arabe. En effet, sans la maîtrise de cette langue, il n’est pas possible à la personne de connaître et de comprendre tous les sens valables du point de vue de la langue pour les expressions qui ont été mentionnées dans la révélation. Nous allons donc à travers ce cours mentionner un certain nombre de textes qui sont sujets à interprétation, et en donner le sens correct du point de vue de la langue arabe et du point de vue de la Loi de l''Islam, en nous référant aux explications données par les savants spécialistes de l’exégèse. Nous parlerons dans un premier temps des preuves du Qour’ān indiquant qu’il existe des versets explicites et des versets non explicites, ainsi que les preuves du ḥadīth concernant leur interprétation (at-ta’wîl) .', 1, 'hadiths, fakhr, d-dîn, ar-râzî'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = 'وَهَذَا لِسَانٌ عَرَبِيٌّ مُّبِينٌ');

-- source: https://islam.ms/sens-hadiths-femme-esclave-jariyah
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Explique le sens du ḥadīth de la femme esclave (al-jāriyah).', 'Al-Qouchayriyy dans son livre', NULL, NULL, 'لاَ يُقَالُ أَيْنَ لِمَنْ أَيَّنَ الأَيْنَ', 'On ne dit pas où pour Celui Qui a créé les où (endroits)', 'lā youqālou ’ayna liman ’ayyana l-’ayn', 'Réponse : An-Nawawiyy dans son commentaire du ḥadīth a dit : « La parole (’ayna l-Lāh) est une interrogation au sujet du mérite (al-makānah) et non au sujet de l’endroit (al-makān) ». Elle signifie : Quelle glorification accordes-tu dans ton cœur pour Allāh ? Et lorsqu’elle a répondu : (Fi s-samā’), cela veut dire qu’Il a un très grand mérite, c’est-à-dire que Allāh mérite une très grande vénération. Il n’est pas permis de croire que le Messager a interrogé cette femme esclave au sujet de l’endroit. Il n’est pas permis non plus de croire que cette femme esclave a voulu dire qu’Il habite le ciel. L’imām ʿAliyy a dit : [rapporté par Al-Qouchayriyy dans son livre Ar-Riçālatou l-Qouchayriyyah]. D’autre part, Aboū Ḥanīfah a dit dans le livre Al-Fiqhou l-’Absaṭ : « Il existe de toute éternité alors qu’Il n’y a pas d’endroit de toute éternité, Il existe alors que de toute éternité, il n’y a ni où ni créatures et Il est Celui Qui est le Créateur de toute chose ». Allāh taʿālā dit :', 1, 'hadiths, explique, sens, femme'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = 'لاَ يُقَالُ أَيْنَ لِمَنْ أَيَّنَ الأَيْنَ');

-- source: https://islam.ms/signification-hadiths-demander-aide
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Qu’est-ce qui est visé par la parole du Messager :', NULL, NULL, NULL, '« إِذَا سَأَلْتَ فَاسْأَلِ اللهَ وَإِذَا اسْتَعَنْتَ فَاسْتَعِن باللهِ »', NULL, '’idhā sa’alta fas’ali l-Lāh wa ’idha-staʿanta fastaʿin bi l-Lāh', 'Réponse : Elle veut dire qu’on demande en priorité à Allāh et on demande l’aide en priorité à Allāh. Elle ne veut pas dire qu’on ne demande à personne d’autre qu’à Allāh ou qu’on ne demande l’aide à personne d’autre qu’à Allāh. Cette parole est similaire au ḥadīth de Ibnou Ḥibbān :', 1, 'hadiths, est-ce, visé, parole'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« إِذَا سَأَلْتَ فَاسْأَلِ اللهَ وَإِذَا اسْتَعَنْتَ فَاسْتَعِن باللهِ »');

-- source: https://islam.ms/tawil-interpretation-qouran-hadiths
INSERT INTO "hadiths" (sujet, rapporteur, narrateur, statut, texte_arabe, texte_francais, phonetique, explication, type_id, tag)
SELECT 'Parle du ta’wīl l’interprétation du Qour’ān et ḥadīth.', 'Al-Boukhāriyy, Ibnou Mājah et le ḥāfiḍh', NULL, NULL, '« اللَّهُمَّ عَلِّمْهُ الحِكْمَةَ وَتَأْوِيلَ الكِتَابِ »', NULL, 'Allāhoumma ʿallimhou l-ḥikmata wa ta’wīla l-kitāb', 'qui signifie : « Ô Allāh, enseigne-lui la sagesse et l’interprétation du Livre » [rapporté par Al-Boukhāriyy, Ibnou Mājah et le ḥāfiḍh Ibnou l-Jawziyy].', 1, 'hadiths, parle, interprétation, qour'
WHERE NOT EXISTS (SELECT 1 FROM "hadiths" WHERE texte_arabe = '« اللَّهُمَّ عَلِّمْهُ الحِكْمَةَ وَتَأْوِيلَ الكِتَابِ »');

COMMIT;
